//! Error handling for GIFTI operations
//!
//! This module provides comprehensive error handling for all GIFTI operations,
//! including XML parsing, data decoding, file I/O, and validation errors.

use std::fmt;
use thiserror::Error;

/// Result type for GIFTI operations
pub type Result<T> = std::result::Result<T, GiftiError>;

/// Comprehensive error types for GIFTI operations
#[derive(Error, Debug)]
pub enum GiftiError {
    /// I/O errors during file operations
    #[error("I/O error: {0}")]
    Io(#[from] std::io::Error),

    /// XML parsing errors
    #[error("XML parsing error: {0}")]
    Xml(#[from] quick_xml::Error),

    /// Invalid GIFTI file format
    #[error("Invalid GIFTI format: {0}")]
    InvalidFormat(String),

    /// Unsupported data type
    #[error("Unsupported data type: {0}")]
    UnsupportedDataType(String),

    /// Unsupported encoding
    #[error("Unsupported encoding: {0}")]
    UnsupportedEncoding(String),

    /// Data decoding errors
    #[error("Data decoding error: {0}")]
    DecodeError(String),

    /// Data encoding errors
    #[error("Data encoding error: {0}")]
    EncodeError(String),

    /// Base64 decoding errors
    #[error("Base64 decoding error: {0}")]
    Base64Error(#[from] base64::DecodeError),

    /// Compression/decompression errors
    #[error("Compression error: {0}")]
    CompressionError(String),

    /// Dimension mismatch errors
    #[error("Dimension mismatch: expected {expected}, got {actual}")]
    DimensionMismatch { expected: usize, actual: usize },

    /// Invalid endianness
    #[error("Invalid endianness: {0}")]
    InvalidEndianness(String),

    /// Invalid intent code
    #[error("Invalid intent code: {0}")]
    InvalidIntent(String),

    /// Missing required element
    #[error("Missing required element: {0}")]
    MissingElement(String),

    /// Invalid attribute value
    #[error("Invalid attribute value for '{attribute}': {value}")]
    InvalidAttribute { attribute: String, value: String },

    /// Data array index out of bounds
    #[error("Data array index out of bounds: {index}")]
    IndexOutOfBounds { index: usize },

    /// External file not found
    #[error("External file not found: {filename}")]
    ExternalFileNotFound { filename: String },

    /// Version mismatch
    #[error("Unsupported GIFTI version: {version}")]
    UnsupportedVersion { version: String },

    /// Validation error
    #[error("Validation error: {0}")]
    ValidationError(String),

    /// UTF-8 conversion error
    #[error("UTF-8 conversion error: {0}")]
    Utf8Error(#[from] std::string::FromUtf8Error),

    /// Number parsing error
    #[error("Number parsing error: {0}")]
    ParseError(String),

    /// Generic error with context
    #[error("GIFTI error: {message}")]
    Generic { message: String },
}

impl GiftiError {
    /// Create a new InvalidFormat error
    pub fn invalid_format(msg: impl Into<String>) -> Self {
        Self::InvalidFormat(msg.into())
    }

    /// Create a new UnsupportedDataType error
    pub fn unsupported_data_type(dtype: impl Into<String>) -> Self {
        Self::UnsupportedDataType(dtype.into())
    }

    /// Create a new UnsupportedEncoding error
    pub fn unsupported_encoding(encoding: impl Into<String>) -> Self {
        Self::UnsupportedEncoding(encoding.into())
    }

    /// Create a new DecodeError
    pub fn decode_error(msg: impl Into<String>) -> Self {
        Self::DecodeError(msg.into())
    }

    /// Create a new EncodeError
    pub fn encode_error(msg: impl Into<String>) -> Self {
        Self::EncodeError(msg.into())
    }

    /// Create a new CompressionError
    pub fn compression_error(msg: impl Into<String>) -> Self {
        Self::CompressionError(msg.into())
    }

    /// Create a new DimensionMismatch error
    pub fn dimension_mismatch(expected: usize, actual: usize) -> Self {
        Self::DimensionMismatch { expected, actual }
    }

    /// Create a new InvalidEndianness error
    pub fn invalid_endianness(endian: impl Into<String>) -> Self {
        Self::InvalidEndianness(endian.into())
    }

    /// Create a new InvalidIntent error
    pub fn invalid_intent(intent: impl Into<String>) -> Self {
        Self::InvalidIntent(intent.into())
    }

    /// Create a new MissingElement error
    pub fn missing_element(element: impl Into<String>) -> Self {
        Self::MissingElement(element.into())
    }

    /// Create a new InvalidAttribute error
    pub fn invalid_attribute(attribute: impl Into<String>, value: impl Into<String>) -> Self {
        Self::InvalidAttribute {
            attribute: attribute.into(),
            value: value.into(),
        }
    }

    /// Create a new IndexOutOfBounds error
    pub fn index_out_of_bounds(index: usize) -> Self {
        Self::IndexOutOfBounds { index }
    }

    /// Create a new ExternalFileNotFound error
    pub fn external_file_not_found(filename: impl Into<String>) -> Self {
        Self::ExternalFileNotFound {
            filename: filename.into(),
        }
    }

    /// Create a new UnsupportedVersion error
    pub fn unsupported_version(version: impl Into<String>) -> Self {
        Self::UnsupportedVersion {
            version: version.into(),
        }
    }

    /// Create a new ValidationError
    pub fn validation_error(msg: impl Into<String>) -> Self {
        Self::ValidationError(msg.into())
    }

    /// Create a new ParseError
    pub fn parse_error(msg: impl Into<String>) -> Self {
        Self::ParseError(msg.into())
    }

    /// Create a new generic error
    pub fn generic(msg: impl Into<String>) -> Self {
        Self::Generic {
            message: msg.into(),
        }
    }
}

