//! Core type definitions for GIFTI files
//!
//! This module defines the fundamental types used throughout the GIFTI format,
//! including data types, encoding formats, endianness, and intent codes.

use crate::error::{GiftiError, Result};
use serde::{Deserialize, Serialize};
use std::fmt;
use std::str::FromStr;

/// GIFTI data types corresponding to NIFTI data types
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum DataType {
    /// Unsigned 8-bit integer
    UInt8,
    /// Signed 32-bit integer
    Int32,
    /// Unsigned 32-bit integer
    UInt32,
    /// 32-bit floating point
    Float32,
}

impl DataType {
    /// Get the size in bytes for this data type
    pub fn size_bytes(&self) -> usize {
        match self {
            DataType::UInt8 => 1,
            DataType::Int32 => 4,
            DataType::UInt32 => 4,
            DataType::Float32 => 4,
        }
    }

    /// Convert to NIFTI type string
    pub fn to_nifti_string(&self) -> &'static str {
        match self {
            DataType::UInt8 => "NIFTI_TYPE_UINT8",
            DataType::Int32 => "NIFTI_TYPE_INT32",
            DataType::UInt32 => "NIFTI_TYPE_UINT32",
            DataType::Float32 => "NIFTI_TYPE_FLOAT32",
        }
    }

    /// Create from NIFTI type string
    pub fn from_nifti_string(s: &str) -> Result<Self> {
        match s {
            "NIFTI_TYPE_UINT8" => Ok(DataType::UInt8),
            "NIFTI_TYPE_INT32" => Ok(DataType::Int32),
            "NIFTI_TYPE_UINT32" => Ok(DataType::UInt32),
            "NIFTI_TYPE_FLOAT32" => Ok(DataType::Float32),
            _ => Err(GiftiError::unsupported_data_type(s)),
        }
    }
}

impl fmt::Display for DataType {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{}", self.to_nifti_string())
    }
}

impl FromStr for DataType {
    type Err = GiftiError;

    fn from_str(s: &str) -> Result<Self> {
        Self::from_nifti_string(s)
    }
}

/// Data encoding formats supported by GIFTI
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum Encoding {
    /// ASCII text encoding
    Ascii,
    /// Base64 binary encoding
    Base64Binary,
    /// GZip compressed Base64 binary encoding
    GZipBase64Binary,
    /// External file binary encoding
    ExternalFileBinary,
}

impl Encoding {
    /// Convert to GIFTI encoding string
    pub fn to_gifti_string(&self) -> &'static str {
        match self {
            Encoding::Ascii => "ASCII",
            Encoding::Base64Binary => "Base64Binary",
            Encoding::GZipBase64Binary => "GZipBase64Binary",
            Encoding::ExternalFileBinary => "ExternalFileBinary",
        }
    }

    /// Create from GIFTI encoding string
    pub fn from_gifti_string(s: &str) -> Result<Self> {
        match s {
            "ASCII" => Ok(Encoding::Ascii),
            "Base64Binary" => Ok(Encoding::Base64Binary),
            "GZipBase64Binary" => Ok(Encoding::GZipBase64Binary),
            "ExternalFileBinary" => Ok(Encoding::ExternalFileBinary),
            _ => Err(GiftiError::unsupported_encoding(s)),
        }
    }
}

impl fmt::Display for Encoding {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{}", self.to_gifti_string())
    }
}

impl FromStr for Encoding {
    type Err = GiftiError;

    fn from_str(s: &str) -> Result<Self> {
        Self::from_gifti_string(s)
    }
}

/// Byte order (endianness) for binary data
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum Endianness {
    /// Big endian byte order
    BigEndian,
    /// Little endian byte order
    LittleEndian,
}

impl Endianness {
    /// Convert to GIFTI endianness string
    pub fn to_gifti_string(&self) -> &'static str {
        match self {
            Endianness::BigEndian => "BigEndian",
            Endianness::LittleEndian => "LittleEndian",
        }
    }

    /// Create from GIFTI endianness string
    pub fn from_gifti_string(s: &str) -> Result<Self> {
        match s {
            "BigEndian" => Ok(Endianness::BigEndian),
            "LittleEndian" => Ok(Endianness::LittleEndian),
            _ => Err(GiftiError::invalid_endianness(s)),
        }
    }

    /// Get the native endianness of the current system
    pub fn native() -> Self {
        if cfg!(target_endian = "big") {
            Endianness::BigEndian
        } else {
            Endianness::LittleEndian
        }
    }
}

impl fmt::Display for Endianness {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{}", self.to_gifti_string())
    }
}

impl FromStr for Endianness {
    type Err = GiftiError;

    fn from_str(s: &str) -> Result<Self> {
        Self::from_gifti_string(s)
    }
}

/// GIFTI intent codes (based on NIFTI intent codes)
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum Intent {
    /// No specific intent
    None,
    /// Spatial coordinate data
    Pointset,
    /// Triangular mesh connectivity
    Triangle,
    /// Quaternion transformations
    Quaternion,
    /// New mesh vertices
    NewMeshVertices,
    /// Functional connectivity dense
    ConnDense,
    /// Functional connectivity dense time
    ConnDenseTime,
    /// Functional connectivity parcellated
    ConnParcellated,
    /// Functional connectivity parcellated time
    ConnParcellatedTime,
    /// Functional connectivity trajectory
    ConnTrajectory,
    /// Functional connectivity trajectory time
    ConnTrajectoryTime,
    /// Shape data
    Shape,
    /// Normal vectors
    Normal,
    /// Curvature data
    Curvature,
    /// Arbitrary scalar data
    Scalar,
    /// Time series data
    TimeSeries,
    /// RGB color data
    RgbVector,
    /// RGBA color data
    RgbaVector,
    /// Label data
    Label,
    /// Generic data
    Generic,
}

impl Intent {
    /// Convert to NIFTI intent string
    pub fn to_nifti_string(&self) -> &'static str {
        match self {
            Intent::None => "NIFTI_INTENT_NONE",
            Intent::Pointset => "NIFTI_INTENT_POINTSET",
            Intent::Triangle => "NIFTI_INTENT_TRIANGLE",
            Intent::Quaternion => "NIFTI_INTENT_QUATERNION",
            Intent::NewMeshVertices => "NIFTI_INTENT_NEW_MESH_VERTICES",
            Intent::ConnDense => "NIFTI_INTENT_CONN_DENSE",
            Intent::ConnDenseTime => "NIFTI_INTENT_CONN_DENSE_TIME",
            Intent::ConnParcellated => "NIFTI_INTENT_CONN_PARCELLATED",
            Intent::ConnParcellatedTime => "NIFTI_INTENT_CONN_PARCELLATED_TIME",
            Intent::ConnTrajectory => "NIFTI_INTENT_CONN_TRAJECTORY",
            Intent::ConnTrajectoryTime => "NIFTI_INTENT_CONN_TRAJECTORY_TIME",
            Intent::Shape => "NIFTI_INTENT_SHAPE",
            Intent::Normal => "NIFTI_INTENT_NORMAL",
            Intent::Curvature => "NIFTI_INTENT_CURVATURE",
            Intent::Scalar => "NIFTI_INTENT_SCALAR",
            Intent::TimeSeries => "NIFTI_INTENT_TIME_SERIES",
            Intent::RgbVector => "NIFTI_INTENT_RGB_VECTOR",
            Intent::RgbaVector => "NIFTI_INTENT_RGBA_VECTOR",
            Intent::Label => "NIFTI_INTENT_LABEL",
            Intent::Generic => "NIFTI_INTENT_GENERIC",
        }
    }

    /// Create from NIFTI intent string
    pub fn from_nifti_string(s: &str) -> Result<Self> {
        match s {
            "NIFTI_INTENT_NONE" => Ok(Intent::None),
            "NIFTI_INTENT_POINTSET" => Ok(Intent::Pointset),
            "NIFTI_INTENT_TRIANGLE" => Ok(Intent::Triangle),
            "NIFTI_INTENT_QUATERNION" => Ok(Intent::Quaternion),
            "NIFTI_INTENT_NEW_MESH_VERTICES" => Ok(Intent::NewMeshVertices),
            "NIFTI_INTENT_CONN_DENSE" => Ok(Intent::ConnDense),
            "NIFTI_INTENT_CONN_DENSE_TIME" => Ok(Intent::ConnDenseTime),
            "NIFTI_INTENT_CONN_PARCELLATED" => Ok(Intent::ConnParcellated),
            "NIFTI_INTENT_CONN_PARCELLATED_TIME" => Ok(Intent::ConnParcellatedTime),
            "NIFTI_INTENT_CONN_TRAJECTORY" => Ok(Intent::ConnTrajectory),
            "NIFTI_INTENT_CONN_TRAJECTORY_TIME" => Ok(Intent::ConnTrajectoryTime),
            "NIFTI_INTENT_SHAPE" => Ok(Intent::Shape),
            "NIFTI_INTENT_NORMAL" => Ok(Intent::Normal),
            "NIFTI_INTENT_CURVATURE" => Ok(Intent::Curvature),
            "NIFTI_INTENT_SCALAR" => Ok(Intent::Scalar),
            "NIFTI_INTENT_TIME_SERIES" => Ok(Intent::TimeSeries),
            "NIFTI_INTENT_RGB_VECTOR" => Ok(Intent::RgbVector),
            "NIFTI_INTENT_RGBA_VECTOR" => Ok(Intent::RgbaVector),
            "NIFTI_INTENT_LABEL" => Ok(Intent::Label),
            "NIFTI_INTENT_GENERIC" => Ok(Intent::Generic),
            _ => Err(GiftiError::invalid_intent(s)),
        }
    }

    /// Get a human-readable name for the intent
    pub fn name(&self) -> &'static str {
        match self {
            Intent::None => "none",
            Intent::Pointset => "pointset",
            Intent::Triangle => "triangle",
            Intent::Quaternion => "quaternion",
            Intent::NewMeshVertices => "new_mesh_vertices",
            Intent::ConnDense => "conn_dense",
            Intent::ConnDenseTime => "conn_dense_time",
            Intent::ConnParcellated => "conn_parcellated",
            Intent::ConnParcellatedTime => "conn_parcellated_time",
            Intent::ConnTrajectory => "conn_trajectory",
            Intent::ConnTrajectoryTime => "conn_trajectory_time",
            Intent::Shape => "shape",
            Intent::Normal => "normal",
            Intent::Curvature => "curvature",
            Intent::Scalar => "scalar",
            Intent::TimeSeries => "timeseries",
            Intent::RgbVector => "rgb_vector",
            Intent::RgbaVector => "rgba_vector",
            Intent::Label => "label",
            Intent::Generic => "generic",
        }
    }
}

impl fmt::Display for Intent {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{}", self.to_nifti_string())
    }
}

impl FromStr for Intent {
    type Err = GiftiError;

    fn from_str(s: &str) -> Result<Self> {
        Self::from_nifti_string(s)
    }
}

/// Array indexing order
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum ArrayIndexingOrder {
    /// Row-major order (C-style)
    RowMajor,
    /// Column-major order (Fortran-style)
    ColumnMajor,
}

impl ArrayIndexingOrder {
    /// Convert to GIFTI string
    pub fn to_gifti_string(&self) -> &'static str {
        match self {
            ArrayIndexingOrder::RowMajor => "RowMajorOrder",
            ArrayIndexingOrder::ColumnMajor => "ColumnMajorOrder",
        }
    }

    /// Create from GIFTI string
    pub fn from_gifti_string(s: &str) -> Result<Self> {
        match s {
            "RowMajorOrder" => Ok(ArrayIndexingOrder::RowMajor),
            "ColumnMajorOrder" => Ok(ArrayIndexingOrder::ColumnMajor),
            _ => Err(GiftiError::invalid_attribute("ArrayIndexingOrder", s)),
        }
    }
}

impl fmt::Display for ArrayIndexingOrder {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{}", self.to_gifti_string())
    }
}

impl FromStr for ArrayIndexingOrder {
    type Err = GiftiError;

    fn from_str(s: &str) -> Result<Self> {
        Self::from_gifti_string(s)
    }
}

