    pub attributes: DataArrayAttributes,
    /// Data array metadata
    pub metadata: MetaData,
    /// Coordinate system transformations
    pub transformations: Vec<CoordinateSystemTransform>,
    /// The actual data as a dynamic n-dimensional array
    pub data: ArrayD<f64>,
}

impl DataArray {
    /// Create a new data array with 1D data
    pub fn new_1d(
        data: Vec<f64>,
        data_type: DataType,
        encoding: Encoding,
        intent: Intent,
    ) -> Result<Self> {
        let len = data.len();
        let dimensions = vec![len];
        let attributes = DataArrayAttributes::new(
            data_type,
            encoding,
            Endianness::native(),
            intent,
            dimensions,
            ArrayIndexingOrder::RowMajor,
        );

        let data_array = Array1::from_vec(data).into_dyn();

        Ok(Self {
            attributes,
            metadata: MetaData::new(),
            transformations: Vec::new(),
            data: data_array,
        })
    }

    /// Create a new data array with 2D data
    pub fn new_2d(
        data: Vec<f64>,
        shape: (usize, usize),
        data_type: DataType,
        encoding: Encoding,
        intent: Intent,
        indexing_order: ArrayIndexingOrder,
    ) -> Result<Self> {
        let dimensions = vec![shape.0, shape.1];
        let attributes = DataArrayAttributes::new(
            data_type,
            encoding,
            Endianness::native(),
            intent,
            dimensions,
            indexing_order,
        );

        if data.len() != shape.0 * shape.1 {
            return Err(GiftiError::dimension_mismatch(shape.0 * shape.1, data.len()));
        }

        let data_array = match indexing_order {
            ArrayIndexingOrder::RowMajor => {
                Array2::from_shape_vec((shape.0, shape.1), data)?.into_dyn()
            }
            ArrayIndexingOrder::ColumnMajor => {
                Array2::from_shape_vec((shape.0, shape.1).f(), data)?.into_dyn()
            }
        };

        Ok(Self {
            attributes,
            metadata: MetaData::new(),
            transformations: Vec::new(),
            data: data_array,
        })
    }

    /// Create a new data array with n-dimensional data
    pub fn new_nd(
        data: Vec<f64>,
        dimensions: Vec<usize>,
        data_type: DataType,
        encoding: Encoding,
        intent: Intent,
        indexing_order: ArrayIndexingOrder,
    ) -> Result<Self> {
        let attributes = DataArrayAttributes::new(
            data_type,
            encoding,
            Endianness::native(),
            intent,
            dimensions.clone(),
            indexing_order,
        );

        let expected_len: usize = dimensions.iter().product();
        if data.len() != expected_len {
            return Err(GiftiError::dimension_mismatch(expected_len, data.len()));
        }

        let shape = IxDyn(&dimensions);
        let data_array = ArrayD::from_shape_vec(shape, data)?;

        Ok(Self {
            attributes,
            metadata: MetaData::new(),
            transformations: Vec::new(),
            data: data_array,
        })
    }

    /// Get the data as a 1D array
    pub fn as_1d(&self) -> Result<Array1<f64>> {
        if !self.attributes.is_1d() {
            return Err(GiftiError::validation_error(format!(
                "Array is not 1D, has {} dimensions",
                self.attributes.dimensionality
            )));
        }
        Ok(self.data.clone().into_dimensionality::<ndarray::Ix1>()?)
    }

    /// Get the data as a 2D array
    pub fn as_2d(&self) -> Result<Array2<f64>> {
        if !self.attributes.is_2d() {
            return Err(GiftiError::validation_error(format!(
                "Array is not 2D, has {} dimensions",
                self.attributes.dimensionality
            )));
        }
        Ok(self.data.clone().into_dimensionality::<ndarray::Ix2>()?)
    }

    /// Get the data as a flat vector
    pub fn as_flat(&self) -> Vec<f64> {
        self.data.iter().copied().collect()
    }

    /// Get the shape of the data array
    pub fn shape(&self) -> &[usize] {
        self.data.shape()
    }

    /// Get the number of dimensions
    pub fn ndim(&self) -> usize {
        self.data.ndim()
    }

    /// Get the number of elements
    pub fn len(&self) -> usize {
        self.data.len()
    }

    /// Check if the array is empty
    pub fn is_empty(&self) -> bool {
        self.data.is_empty()
    }

    /// Add metadata
    pub fn add_metadata(&mut self, key: String, value: String) {
        self.metadata.insert(key, value);
    }

    /// Add a coordinate system transformation
    pub fn add_transformation(&mut self, transform: CoordinateSystemTransform) {
        self.transformations.push(transform);
    }

    /// Get the intent name
    pub fn intent_name(&self) -> &'static str {
        self.attributes.intent.name()
    }

    /// Validate the data array
    pub fn validate(&self) -> Result<()> {
        self.attributes.validate()?;

        // Check that data dimensions match attributes
        if self.data.shape() != self.attributes.dimensions.as_slice() {
            return Err(GiftiError::validation_error(format!(
                "Data shape {:?} does not match attributes dimensions {:?}",
                self.data.shape(),
                self.attributes.dimensions
            )));
        }

        // Validate transformations
        for transform in &self.transformations {
            if !transform.is_invertible() {
                log::warn!(
                    "Transformation matrix from {} to {} is not invertible",
                    transform.data_space,
                    transform.transformed_space
                );
            }
        }

        Ok(())
    }

    /// Check if this data array represents pointset data
    pub fn is_pointset(&self) -> bool {
        matches!(self.attributes.intent, Intent::Pointset)
    }

    /// Check if this data array represents triangle data
    pub fn is_triangle(&self) -> bool {
        matches!(self.attributes.intent, Intent::Triangle)
    }

    /// Check if this data array represents shape data
    pub fn is_shape(&self) -> bool {
        matches!(self.attributes.intent, Intent::Shape)
    }

    /// Check if this data array represents time series data
    pub fn is_timeseries(&self) -> bool {
        matches!(self.attributes.intent, Intent::TimeSeries)
    }

    /// Check if this data array represents label data
    pub fn is_label(&self) -> bool {
        matches!(self.attributes.intent, Intent::Label)
    }
}

// Implement conversion from ndarray errors
impl From<ndarray::ShapeError> for GiftiError {
    fn from(err: ndarray::ShapeError) -> Self {
        GiftiError::validation_error(format!("Array shape error: {}", err))
    }
}

