//! Main GIFTI structure and implementation
//!
//! This module contains the main `Gifti` struct that represents a complete
//! GIFTI file with all its data arrays, metadata, and label tables.

use crate::core::data_array::DataArray;
use crate::core::metadata::{LabelTable, MetaData};
use crate::core::types::Intent;
use crate::error::{GiftiError, Result};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;

/// Main GIFTI structure representing a complete GIFTI file
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct Gifti {
    /// GIFTI format version
    pub version: String,
    /// File-level metadata
    pub metadata: MetaData,
    /// Label table for categorical data
    pub label_table: Option<LabelTable>,
    /// Data arrays contained in the file
    pub data_arrays: Vec<DataArray>,
}

impl Gifti {
    /// Create a new empty GIFTI structure
    pub fn new() -> Self {
        Self {
            version: "1.0".to_string(),
            metadata: MetaData::new(),
            label_table: None,
            data_arrays: Vec::new(),
        }
    }

    /// Create a new GIFTI structure with specified version
    pub fn with_version(version: String) -> Self {
        Self {
            version,
            metadata: MetaData::new(),
            label_table: None,
            data_arrays: Vec::new(),
        }
    }

    /// Add a data array to the GIFTI file
    pub fn add_data_array(&mut self, data_array: DataArray) {
        self.data_arrays.push(data_array);
    }

    /// Get the number of data arrays
    pub fn num_data_arrays(&self) -> usize {
        self.data_arrays.len()
    }

    /// Get a data array by index
    pub fn get_data_array(&self, index: usize) -> Option<&DataArray> {
        self.data_arrays.get(index)
    }

    /// Get a mutable reference to a data array by index
    pub fn get_data_array_mut(&mut self, index: usize) -> Option<&mut DataArray> {
        self.data_arrays.get_mut(index)
    }

    /// Get data arrays by intent
    pub fn get_data_arrays_by_intent(&self, intent: Intent) -> Vec<&DataArray> {
        self.data_arrays
            .iter()
            .filter(|array| array.attributes.intent == intent)
            .collect()
    }

    /// Get the first data array with the specified intent
    pub fn get_first_data_array_by_intent(&self, intent: Intent) -> Option<&DataArray> {
        self.data_arrays
            .iter()
            .find(|array| array.attributes.intent == intent)
    }

    /// Add file-level metadata
    pub fn add_metadata(&mut self, key: String, value: String) {
        self.metadata.insert(key, value);
    }

    /// Get file-level metadata
    pub fn get_metadata(&self, key: &str) -> Option<&String> {
        self.metadata.get(key)
    }

    /// Set the label table
    pub fn set_label_table(&mut self, label_table: LabelTable) {
        self.label_table = Some(label_table);
    }

    /// Get the label table
    pub fn get_label_table(&self) -> Option<&LabelTable> {
        self.label_table.as_ref()
    }

    /// Get a mutable reference to the label table
    pub fn get_label_table_mut(&mut self) -> Option<&mut LabelTable> {
        self.label_table.as_mut()
    }

    /// Check if this GIFTI file contains pointset data
    pub fn has_pointset(&self) -> bool {
        self.data_arrays.iter().any(|array| array.is_pointset())
    }

    /// Check if this GIFTI file contains triangle data
    pub fn has_triangles(&self) -> bool {
        self.data_arrays.iter().any(|array| array.is_triangle())
    }

    /// Check if this GIFTI file contains shape data
    pub fn has_shape(&self) -> bool {
        self.data_arrays.iter().any(|array| array.is_shape())
    }

    /// Check if this GIFTI file contains time series data
    pub fn has_timeseries(&self) -> bool {
        self.data_arrays.iter().any(|array| array.is_timeseries())
    }

    /// Check if this GIFTI file contains label data
    pub fn has_labels(&self) -> bool {
        self.data_arrays.iter().any(|array| array.is_label())
    }

    /// Get pointset data (vertices)
    pub fn get_pointset(&self) -> Option<&DataArray> {
        self.get_first_data_array_by_intent(Intent::Pointset)
    }

    /// Get triangle data (connectivity)
    pub fn get_triangles(&self) -> Option<&DataArray> {
        self.get_first_data_array_by_intent(Intent::Triangle)
    }

    /// Get shape data
    pub fn get_shape(&self) -> Option<&DataArray> {
        self.get_first_data_array_by_intent(Intent::Shape)
    }

    /// Get time series data arrays
    pub fn get_timeseries(&self) -> Vec<&DataArray> {
        self.get_data_arrays_by_intent(Intent::TimeSeries)
    }

    /// Get label data
    pub fn get_labels(&self) -> Option<&DataArray> {
        self.get_first_data_array_by_intent(Intent::Label)
    }

    /// Check if this is a surface file (has both pointset and triangles)
    pub fn is_surface(&self) -> bool {
        self.has_pointset() && self.has_triangles()
    }

    /// Check if this is a shape file (has shape data)
    pub fn is_shape_file(&self) -> bool {
        self.has_shape()
    }

    /// Check if this is a time series file (has time series data)
    pub fn is_timeseries_file(&self) -> bool {
        self.has_timeseries()
    }

    /// Check if this is a label file (has label data and label table)
    pub fn is_label_file(&self) -> bool {
        self.has_labels() && self.label_table.is_some()
    }

    /// Get surface data as pointset and triangles
    pub fn get_surface_data(&self) -> Option<(&DataArray, &DataArray)> {
        if let (Some(pointset), Some(triangles)) = (self.get_pointset(), self.get_triangles()) {
            Some((pointset, triangles))
        } else {
            None
        }
    }

    /// Get a summary of the GIFTI file contents
    pub fn summary(&self) -> GiftiSummary {
        let mut intent_counts = HashMap::new();
        for array in &self.data_arrays {
            *intent_counts.entry(array.attributes.intent).or_insert(0) += 1;
        }

        GiftiSummary {
            version: self.version.clone(),
            num_data_arrays: self.data_arrays.len(),
            has_metadata: !self.metadata.is_empty(),
            has_label_table: self.label_table.is_some(),
            intent_counts,
            is_surface: self.is_surface(),
            is_shape_file: self.is_shape_file(),
            is_timeseries_file: self.is_timeseries_file(),
            is_label_file: self.is_label_file(),
        }
    }

    /// Validate the entire GIFTI structure
    pub fn validate(&self) -> Result<()> {
        // Validate version
        if self.version.is_empty() {
            return Err(GiftiError::validation_error(
                "GIFTI version cannot be empty".to_string(),
            ));
        }

        // Validate that we have at least one data array
        if self.data_arrays.is_empty() {
            return Err(GiftiError::validation_error(
                "GIFTI file must contain at least one data array".to_string(),
            ));
        }

        // Validate each data array
        for (i, array) in self.data_arrays.iter().enumerate() {
            array.validate().map_err(|e| {
                GiftiError::validation_error(format!("Data array {} validation failed: {}", i, e))
            })?;
        }

        // Validate label table if present
        if let Some(label_table) = &self.label_table {
            label_table.validate()?;
        }

        // Validate consistency between label data and label table
        if self.has_labels() && self.label_table.is_none() {
            log::warn!("GIFTI file has label data but no label table");
        }

        // Validate surface consistency
        if self.is_surface() {
            if let Some((pointset, triangles)) = self.get_surface_data() {
                let num_vertices = pointset.shape()[0];
                let triangle_data = triangles.as_flat();

                // Check that triangle indices are valid (converted to 0-based)
                for &index in &triangle_data {
                    let vertex_index = index as usize;
                    if vertex_index >= num_vertices {
                        return Err(GiftiError::validation_error(format!(
                            "Triangle vertex index {} exceeds number of vertices {}",
                            vertex_index, num_vertices
                        )));
                    }
                }
            }
        }

        Ok(())
    }
}

impl Default for Gifti {
    fn default() -> Self {
        Self::new()
    }
}

/// Summary information about a GIFTI file
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct GiftiSummary {
    /// GIFTI format version
    pub version: String,
    /// Number of data arrays
    pub num_data_arrays: usize,
    /// Whether file has metadata
    pub has_metadata: bool,
    /// Whether file has a label table
    pub has_label_table: bool,
    /// Count of arrays by intent type
    pub intent_counts: HashMap<Intent, usize>,
    /// Whether this is a surface file
    pub is_surface: bool,
    /// Whether this is a shape file
    pub is_shape_file: bool,
    /// Whether this is a time series file
    pub is_timeseries_file: bool,
    /// Whether this is a label file
    pub is_label_file: bool,
}

impl GiftiSummary {
    /// Get the file type as a string
    pub fn file_type(&self) -> &'static str {
        if self.is_surface {
            "Surface"
        } else if self.is_shape_file {
            "Shape"
        } else if self.is_timeseries_file {
            "Time Series"
        } else if self.is_label_file {
            "Label"
        } else {
            "Generic"
        }
    }

    /// Get a list of all intents present in the file
    pub fn intents(&self) -> Vec<Intent> {
        self.intent_counts.keys().copied().collect()
    }

    /// Get the total number of data elements across all arrays
    pub fn total_elements(&self) -> usize {
        // Note: This would need access to the actual arrays to calculate
        // For now, we'll return 0 as a placeholder
        0
    }
}

impl std::fmt::Display for GiftiSummary {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        writeln!(f, "GIFTI File Summary:")?;
        writeln!(f, "  Version: {}", self.version)?;
        writeln!(f, "  Type: {}", self.file_type())?;
        writeln!(f, "  Data Arrays: {}", self.num_data_arrays)?;
        writeln!(f, "  Has Metadata: {}", self.has_metadata)?;
        writeln!(f, "  Has Label Table: {}", self.has_label_table)?;
        writeln!(f, "  Intent Counts:")?;
        for (intent, count) in &self.intent_counts {
            writeln!(f, "    {}: {}", intent.name(), count)?;
        }
        Ok(())
    }
}

