        for (i, array) in self.data_arrays.iter().enumerate() {
            array.validate().map_err(|e| {
                GiftiError::validation_error(format!("Data array {} validation failed: {}", i, e))
            })?;
        }

        // Validate label table if present
        if let Some(label_table) = &self.label_table {
            label_table.validate()?;
        }

        // Validate consistency between label data and label table
        if self.has_labels() && self.label_table.is_none() {
