//! Data decoding utilities for GIFTI files
//!
//! This module provides functions to decode data from various GIFTI encoding
//! formats including ASCII, Base64Binary, GZipBase64Binary, and ExternalFileBinary.

use crate::core::types::{DataType, Encoding, Endianness};
use crate::error::{GiftiError, Result};
use base64::{engine::general_purpose, Engine as _};
use byteorder::{BigEndian, LittleEndian, ReadBytesExt};
use flate2::read::GzDecoder;
use std::io::{Cursor, Read};
use std::path::Path;

/// Decode data from a GIFTI data array
pub fn decode_data(
    data_text: &str,
    encoding: Encoding,
    data_type: DataType,
    endianness: Endianness,
    external_filename: Option<&str>,
    expected_elements: usize,
) -> Result<Vec<f64>> {
    match encoding {
        Encoding::Ascii => decode_ascii(data_text, expected_elements),
        Encoding::Base64Binary => decode_base64_binary(data_text, data_type, endianness, expected_elements),
        Encoding::GZipBase64Binary => decode_gzip_base64_binary(data_text, data_type, endianness, expected_elements),
        Encoding::ExternalFileBinary => {
            let filename = external_filename.ok_or_else(|| {
                GiftiError::decode_error("External filename required for ExternalFileBinary encoding")
            })?;
            decode_external_file_binary(filename, data_type, endianness, expected_elements)
        }
    }
}

/// Decode ASCII data
fn decode_ascii(data_text: &str, expected_elements: usize) -> Result<Vec<f64>> {
    let mut values = Vec::new();

    // Split by whitespace and parse each value
    for token in data_text.split_whitespace() {
        if token.is_empty() {
            continue;
        }

        let value = token.parse::<f64>().map_err(|e| {
            GiftiError::decode_error(format!("Failed to parse ASCII value '{}': {}", token, e))
        })?;

        values.push(value);
    }

    if values.len() != expected_elements {
        return Err(GiftiError::dimension_mismatch(expected_elements, values.len()));
    }

    Ok(values)
}

/// Decode Base64 binary data
fn decode_base64_binary(
    data_text: &str,
    data_type: DataType,
    endianness: Endianness,
    expected_elements: usize,
) -> Result<Vec<f64>> {
    // Remove whitespace and decode base64
    let clean_data = data_text.chars().filter(|c| !c.is_whitespace()).collect::<String>();
    let binary_data = general_purpose::STANDARD.decode(clean_data)?;

    decode_binary_data(&binary_data, data_type, endianness, expected_elements)
}

/// Decode GZip compressed Base64 binary data
fn decode_gzip_base64_binary(
    data_text: &str,
    data_type: DataType,
    endianness: Endianness,
    expected_elements: usize,
) -> Result<Vec<f64>> {
    // Remove whitespace and decode base64
    let clean_data = data_text.chars().filter(|c| !c.is_whitespace()).collect::<String>();
    let compressed_data = general_purpose::STANDARD.decode(clean_data)?;

    // Decompress with gzip
    let mut decompressor = GzDecoder::new(&compressed_data[..]);
    let mut binary_data = Vec::new();
    decompressor.read_to_end(&mut binary_data).map_err(|e| {
        GiftiError::compression_error(format!("Failed to decompress gzip data: {}", e))
    })?;

    decode_binary_data(&binary_data, data_type, endianness, expected_elements)
}

/// Decode data from an external binary file
fn decode_external_file_binary(
    filename: &str,
    data_type: DataType,
    endianness: Endianness,
    expected_elements: usize,
) -> Result<Vec<f64>> {
    let path = Path::new(filename);
    if !path.exists() {
        return Err(GiftiError::external_file_not_found(filename));
    }

    let binary_data = std::fs::read(path).map_err(|e| {
        GiftiError::decode_error(format!("Failed to read external file '{}': {}", filename, e))
    })?;

    decode_binary_data(&binary_data, data_type, endianness, expected_elements)
}

/// Decode binary data based on data type and endianness
fn decode_binary_data(
    binary_data: &[u8],
    data_type: DataType,
    endianness: Endianness,
    expected_elements: usize,
) -> Result<Vec<f64>> {
    let element_size = data_type.size_bytes();
    let expected_bytes = expected_elements * element_size;

    if binary_data.len() != expected_bytes {
        return Err(GiftiError::decode_error(format!(
            "Binary data size mismatch: expected {} bytes, got {}",
            expected_bytes,
            binary_data.len()
        )));
    }

    let mut cursor = Cursor::new(binary_data);
    let mut values = Vec::with_capacity(expected_elements);

    match (data_type, endianness) {
        (DataType::UInt8, _) => {
            for _ in 0..expected_elements {
                let value = cursor.read_u8().map_err(|e| {
                    GiftiError::decode_error(format!("Failed to read UINT8 value: {}", e))
                })?;
                values.push(value as f64);
            }
        }
        (DataType::Int32, Endianness::BigEndian) => {
            for _ in 0..expected_elements {
                let value = cursor.read_i32::<BigEndian>().map_err(|e| {
                    GiftiError::decode_error(format!("Failed to read INT32 value: {}", e))
                })?;
                values.push(value as f64);
            }
        }
        (DataType::Int32, Endianness::LittleEndian) => {
            for _ in 0..expected_elements {
                let value = cursor.read_i32::<LittleEndian>().map_err(|e| {
                    GiftiError::decode_error(format!("Failed to read INT32 value: {}", e))
                })?;
                values.push(value as f64);
            }
        }
        (DataType::UInt32, Endianness::BigEndian) => {
            for _ in 0..expected_elements {
                let value = cursor.read_u32::<BigEndian>().map_err(|e| {
                    GiftiError::decode_error(format!("Failed to read UINT32 value: {}", e))
                })?;
                values.push(value as f64);
            }
        }
        (DataType::UInt32, Endianness::LittleEndian) => {
            for _ in 0..expected_elements {
                let value = cursor.read_u32::<LittleEndian>().map_err(|e| {
                    GiftiError::decode_error(format!("Failed to read UINT32 value: {}", e))
                })?;
                values.push(value as f64);
            }
        }
        (DataType::Float32, Endianness::BigEndian) => {
            for _ in 0..expected_elements {
                let value = cursor.read_f32::<BigEndian>().map_err(|e| {
                    GiftiError::decode_error(format!("Failed to read FLOAT32 value: {}", e))
                })?;
                values.push(value as f64);
            }
        }
        (DataType::Float32, Endianness::LittleEndian) => {
            for _ in 0..expected_elements {
                let value = cursor.read_f32::<LittleEndian>().map_err(|e| {
                    GiftiError::decode_error(format!("Failed to read FLOAT32 value: {}", e))
                })?;
                values.push(value as f64);
            }
        }
    }

    Ok(values)
}

/// Validate decoded data for potential issues
pub fn validate_decoded_data(data: &[f64], data_type: DataType) -> Result<()> {
    for (i, &value) in data.iter().enumerate() {
        // Check for NaN values
        if value.is_nan() {
            log::warn!("NaN value found at index {}", i);
        }

        // Check for infinite values
        if value.is_infinite() {
            log::warn!("Infinite value found at index {}", i);
        }

        // Check data type specific ranges
        match data_type {
            DataType::UInt8 => {
                if value < 0.0 || value > 255.0 {
                    log::warn!("UINT8 value {} at index {} is out of range [0, 255]", value, i);
                }
            }
            DataType::Int32 => {
                if value < i32::MIN as f64 || value > i32::MAX as f64 {
                    log::warn!("INT32 value {} at index {} is out of range", value, i);
                }
            }
            DataType::UInt32 => {
                if value < 0.0 || value > u32::MAX as f64 {
                    log::warn!("UINT32 value {} at index {} is out of range", value, i);
                }
            }
            DataType::Float32 => {
                // Float32 can represent a wide range, just check for extreme values
                if value.abs() > f32::MAX as f64 {
                    log::warn!("FLOAT32 value {} at index {} may lose precision", value, i);
                }
            }
        }
    }

    Ok(())
}

