//! XML parsing and generation utilities for GIFTI files
//!
//! This module provides functions to parse GIFTI XML files and generate
//! XML output, handling the specific structure and requirements of the
//! GIFTI format.

use crate::core::data_array::{DataArray, DataArrayAttributes};
use crate::core::gifti::Gifti;
use crate::core::metadata::{CoordinateSystemTransform, Label, LabelTable, MetaData};
use crate::core::types::{ArrayIndexingOrder, DataType, Encoding, Endianness, Intent};
use crate::error::{GiftiError, Result};
use crate::io::decoder::decode_data;
use indexmap::IndexMap;
use quick_xml::events::{BytesEnd, BytesStart, BytesText, Event};
use quick_xml::{Reader, Writer};
use std::collections::HashMap;
use std::io::{BufRead, BufReader, Cursor, Write};
use std::str;

/// Parse a GIFTI XML file from a reader
pub fn parse_gifti_xml<R: BufRead>(reader: R) -> Result<Gifti> {
    let mut xml_reader = Reader::from_reader(reader);
    xml_reader.config_mut().trim_text(true);

    let mut gifti = Gifti::new();
    let mut buf = Vec::new();

    // Parse the root GIFTI element
    loop {
        match xml_reader.read_event_into(&mut buf)? {
            Event::Start(ref e) | Event::Empty(ref e) => {
                if e.name().as_ref() == b"GIFTI" {
                    parse_gifti_element(&mut xml_reader, &mut gifti, e)?;
                    break;
                }
            }
            Event::Eof => {
                return Err(GiftiError::invalid_format("No GIFTI root element found"));
            }
            _ => {}
        }
        buf.clear();
    }

    Ok(gifti)
}

/// Parse the main GIFTI element attributes and children
fn parse_gifti_element<R: BufRead>(
    reader: &mut Reader<R>,
    gifti: &mut Gifti,
    start_element: &BytesStart,
) -> Result<()> {
    // Parse attributes
    for attr in start_element.attributes() {
