                        gifti.add_data_array(data_array);
                    }
                    _ => {
                        // Skip unknown elements
                        skip_element(reader)?;
                    }
                }
            }
            Event::End(ref e) => {
                if e.name().as_ref() == b"GIFTI" {
                    break;
                }
            }
            Event::Eof => {
                return Err(GiftiError::invalid_format("Unexpected end of file"));
            }
            _ => {}
        }
        buf.clear();
    }

    Ok(())
}

/// Parse a MetaData element
fn parse_metadata_element<R: BufRead>(
    reader: &mut Reader<R>,
    _start_element: &BytesStart,
) -> Result<MetaData> {
    let mut metadata = MetaData::new();
    let mut buf = Vec::new();

    loop {
        match reader.read_event_into(&mut buf)? {
            Event::Start(ref e) => {
                let name = str::from_utf8(e.name().as_ref())?;
                if name == "MD" {
                    let (key, value) = parse_md_element(reader, e)?;
                    metadata.insert(key, value);
                } else {
                    skip_element(reader)?;
                }
            }
            Event::End(ref e) => {
                if e.name().as_ref() == b"MetaData" {
