/// Parse a Label element
fn parse_label_element<R: BufRead>(
    reader: &mut Reader<R>,
    start_element: &BytesStart,
) -> Result<Label> {
    let mut index = 0u32;
    let mut red = 1.0f32;
    let mut green = 1.0f32;
    let mut blue = 1.0f32;
    let mut alpha = 1.0f32;

    // Parse attributes
    for attr in start_element.attributes() {
        let attr = attr?;
        let key = str::from_utf8(attr.key.as_ref())?;
        let value = str::from_utf8(&attr.value)?;

        match key {
            "Index" => {
                index = value.parse().map_err(|e| {
                    GiftiError::parse_error(format!("Invalid label index: {}", e))
                })?;
            }
            "Red" => {
                red = value.parse().map_err(|e| {
                    GiftiError::parse_error(format!("Invalid red value: {}", e))
                })?;
            }
            "Green" => {
                green = value.parse().map_err(|e| {
                    GiftiError::parse_error(format!("Invalid green value: {}", e))
                })?;
            }
            "Blue" => {
                blue = value.parse().map_err(|e| {
                    GiftiError::parse_error(format!("Invalid blue value: {}", e))
                })?;
            }
            "Alpha" => {
                alpha = value.parse().map_err(|e| {
                    GiftiError::parse_error(format!("Invalid alpha value: {}", e))
                })?;
            }
            _ => {
                // Unknown attribute, ignore
            }
        }
    }

    // Read the label text
    let text = read_text_content(reader, "Label")?;

    Ok(Label::new(index, text, red, green, blue, alpha))
