/// Parse a GIFTI XML file from a reader
pub fn parse_gifti_xml<R: BufRead>(reader: R) -> Result<Gifti> {
    let mut xml_reader = Reader::from_reader(reader);
    xml_reader.config_mut().trim_text(true);

    let mut gifti = Gifti::new();
    let mut buf = Vec::new();

    // Parse the root GIFTI element
    loop {
        match xml_reader.read_event_into(&mut buf)? {
            Event::Start(ref e) | Event::Empty(ref e) => {
                if e.name().as_ref() == b"GIFTI" {
                    parse_gifti_element(&mut xml_reader, &mut gifti, e)?;
                    break;
                }
            }
            Event::Eof => {
                return Err(GiftiError::invalid_format("No GIFTI root element found"));
            }
            _ => {}
        }
        buf.clear();
    }

    Ok(gifti)
}

/// Parse the main GIFTI element attributes and children
fn parse_gifti_element<R: BufRead>(
    reader: &mut Reader<R>,
    gifti: &mut Gifti,
    start_element: &BytesStart,
) -> Result<()> {
    // Parse attributes
    for attr in start_element.attributes() {
        let attr = attr?;
        let key = str::from_utf8(attr.key.as_ref())?;
        let value = str::from_utf8(&attr.value)?;

        match key {
            "Version" => {
                gifti.version = value.to_string();
            }
            "NumberOfDataArrays" => {
                let expected_arrays: usize = value.parse().map_err(|e| {
                    GiftiError::parse_error(format!("Invalid NumberOfDataArrays: {}", e))
                })?;
                gifti.data_arrays.reserve(expected_arrays);
            }
            _ => {
                // Store other attributes as metadata
                gifti.add_metadata(key.to_string(), value.to_string());
            }
        }
    }

    // Parse child elements
    let mut buf = Vec::new();
    loop {
        match reader.read_event_into(&mut buf)? {
            Event::Start(ref e) => {
                let name = str::from_utf8(e.name().as_ref())?;
                match name {
                    "MetaData" => {
                        let metadata = parse_metadata_element(reader, e)?;
                        gifti.metadata = metadata;
                    }
                    "LabelTable" => {
                        let label_table = parse_label_table_element(reader, e)?;
                        gifti.set_label_table(label_table);
                    }
