                        let data_array = parse_data_array_element(reader, e)?;
                        gifti.add_data_array(data_array);
                    }
                    _ => {
                        // Skip unknown elements
                        skip_element(reader)?;
                    }
                }
            }
            Event::End(ref e) => {
                if e.name().as_ref() == b"GIFTI" {
                    break;
                }
            }
            Event::Eof => {
                return Err(GiftiError::invalid_format("Unexpected end of file"));
            }
            _ => {}
        }
        buf.clear();
    }

    Ok(())
}

/// Parse a MetaData element
fn parse_metadata_element<R: BufRead>(
    reader: &mut Reader<R>,
