        writeln!(f, "  Path: {}", self.path.display())?;
        writeln!(f, "  Size: {}", self.size_human_readable())?;
        writeln!(f, "  Compressed: {}", self.is_compressed)?;
        writeln!(f, "  Version: {}", self.version)?;
        writeln!(f, "  Data Arrays: {}", self.num_data_arrays)?;
        Ok(())
    }
}

