//! Conversion utilities for GIFTI types
//!
//! This module provides functions to convert between different GIFTI types
//! and formats, matching the functionality of the R package conversion functions.

use crate::core::types::{DataType, Encoding, Endianness, Intent};
use crate::error::{GiftiError, Result};

/// Convert GIFTI intent code to human-readable name
/// 
/// This function matches the behavior of the R `convert_intent` function,
/// providing a mapping from NIFTI intent codes to readable names.
pub fn convert_intent(intent: Intent) -> &'static str {
    intent.name()
}

/// Convert GIFTI intent code from string to enum
pub fn convert_intent_from_string(intent_str: &str) -> Result<Intent> {
    Intent::from_nifti_string(intent_str)
}

/// Convert endianness from string to enum
/// 
/// This function matches the behavior of the R `convert_endian` function.
pub fn convert_endian(endian_str: &str) -> Result<Endianness> {
    Endianness::from_gifti_string(endian_str)
}

/// Convert endianness enum to string
pub fn convert_endian_to_string(endianness: Endianness) -> &'static str {
    endianness.to_gifti_string()
}

/// Convert binary data type information
/// 
/// This function matches the behavior of the R `convert_binary_datatype` function,
/// providing information about binary data types used in GIFTI files.
pub fn convert_binary_datatype(data_type: DataType) -> BinaryDataTypeInfo {
    match data_type {
        DataType::UInt8 => BinaryDataTypeInfo {
            size_bytes: 1,
            signed: false,
            floating_point: false,
            name: "UINT8",
            description: "Unsigned 8-bit integer",
        },
        DataType::Int32 => BinaryDataTypeInfo {
            size_bytes: 4,
            signed: true,
            floating_point: false,
            name: "INT32",
            description: "Signed 32-bit integer",
        },
        DataType::UInt32 => BinaryDataTypeInfo {
            size_bytes: 4,
            signed: false,
            floating_point: false,
            name: "UINT32",
            description: "Unsigned 32-bit integer",
        },
        DataType::Float32 => BinaryDataTypeInfo {
            size_bytes: 4,
            signed: true,
            floating_point: true,
            name: "FLOAT32",
            description: "32-bit floating point",
        },
    }
}

/// Information about binary data types
#[derive(Debug, Clone, PartialEq)]
pub struct BinaryDataTypeInfo {
    /// Size in bytes
    pub size_bytes: usize,
    /// Whether the type is signed
    pub signed: bool,
    /// Whether the type is floating point
    pub floating_point: bool,
    /// Short name
    pub name: &'static str,
    /// Human-readable description
    pub description: &'static str,
}

/// Convert data type from string to enum
pub fn convert_datatype_from_string(datatype_str: &str) -> Result<DataType> {
    DataType::from_nifti_string(datatype_str)
}

/// Convert data type enum to string
pub fn convert_datatype_to_string(data_type: DataType) -> &'static str {
    data_type.to_nifti_string()
}

/// Convert encoding from string to enum
pub fn convert_encoding_from_string(encoding_str: &str) -> Result<Encoding> {
    Encoding::from_gifti_string(encoding_str)
}

/// Convert encoding enum to string
pub fn convert_encoding_to_string(encoding: Encoding) -> &'static str {
    encoding.to_gifti_string()
}

/// Get the native endianness of the current system
pub fn get_native_endianness() -> Endianness {
    Endianness::native()
}

/// Check if endianness conversion is needed
pub fn needs_endian_conversion(source: Endianness, target: Endianness) -> bool {
    source != target
}

/// Convert a value based on endianness
pub fn convert_endian_value(value: u32, from: Endianness, to: Endianness) -> u32 {
    if from == to {
        value
    } else {
        value.swap_bytes()
    }
}

/// Get all supported intent codes
pub fn get_all_intents() -> Vec<Intent> {
    vec![
        Intent::None,
        Intent::Pointset,
        Intent::Triangle,
        Intent::Quaternion,
        Intent::NewMeshVertices,
        Intent::ConnDense,
        Intent::ConnDenseTime,
        Intent::ConnParcellated,
        Intent::ConnParcellatedTime,
        Intent::ConnTrajectory,
        Intent::ConnTrajectoryTime,
        Intent::Shape,
        Intent::Normal,
        Intent::Curvature,
        Intent::Scalar,
        Intent::TimeSeries,
        Intent::RgbVector,
        Intent::RgbaVector,
        Intent::Label,
        Intent::Generic,
    ]
}

/// Get all supported data types
pub fn get_all_datatypes() -> Vec<DataType> {
    vec![
        DataType::UInt8,
        DataType::Int32,
        DataType::UInt32,
        DataType::Float32,
    ]
}

/// Get all supported encodings
pub fn get_all_encodings() -> Vec<Encoding> {
    vec![
        Encoding::Ascii,
        Encoding::Base64Binary,
        Encoding::GZipBase64Binary,
        Encoding::ExternalFileBinary,
    ]
}

/// Get all supported endianness values
pub fn get_all_endianness() -> Vec<Endianness> {
    vec![Endianness::BigEndian, Endianness::LittleEndian]
}

/// Check if a data type is integer
pub fn is_integer_datatype(data_type: DataType) -> bool {
    matches!(data_type, DataType::UInt8 | DataType::Int32 | DataType::UInt32)
}

/// Check if a data type is floating point
pub fn is_float_datatype(data_type: DataType) -> bool {
    matches!(data_type, DataType::Float32)
}

/// Check if a data type is signed
pub fn is_signed_datatype(data_type: DataType) -> bool {
    matches!(data_type, DataType::Int32 | DataType::Float32)
}

/// Check if a data type is unsigned
pub fn is_unsigned_datatype(data_type: DataType) -> bool {
    matches!(data_type, DataType::UInt8 | DataType::UInt32)
}

/// Get the minimum value for a data type
pub fn get_datatype_min(data_type: DataType) -> f64 {
    match data_type {
        DataType::UInt8 => 0.0,
        DataType::Int32 => i32::MIN as f64,
        DataType::UInt32 => 0.0,
        DataType::Float32 => f32::MIN as f64,
    }
}

/// Get the maximum value for a data type
pub fn get_datatype_max(data_type: DataType) -> f64 {
    match data_type {
        DataType::UInt8 => u8::MAX as f64,
        DataType::Int32 => i32::MAX as f64,
        DataType::UInt32 => u32::MAX as f64,
        DataType::Float32 => f32::MAX as f64,
    }
}

/// Check if an encoding requires external files
pub fn requires_external_file(encoding: Encoding) -> bool {
    matches!(encoding, Encoding::ExternalFileBinary)
}

/// Check if an encoding uses compression
pub fn uses_compression(encoding: Encoding) -> bool {
    matches!(encoding, Encoding::GZipBase64Binary)
}

/// Check if an encoding uses base64
pub fn uses_base64(encoding: Encoding) -> bool {
    matches!(encoding, Encoding::Base64Binary | Encoding::GZipBase64Binary)
}

/// Check if an encoding is text-based
pub fn is_text_encoding(encoding: Encoding) -> bool {
    matches!(encoding, Encoding::Ascii)
}

/// Check if an encoding is binary
pub fn is_binary_encoding(encoding: Encoding) -> bool {
    !is_text_encoding(encoding)
}

