mod tests {
    use super::*;

    #[test]
    fn test_convert_intent() {
        assert_eq!(convert_intent(Intent::Pointset), "pointset");
        assert_eq!(convert_intent(Intent::Triangle), "triangle");
        assert_eq!(convert_intent(Intent::Shape), "shape");
        assert_eq!(convert_intent(Intent::TimeSeries), "timeseries");
    }

    #[test]
    fn test_convert_intent_from_string() {
        assert_eq!(
            convert_intent_from_string("NIFTI_INTENT_POINTSET").unwrap(),
            Intent::Pointset
        );
        assert_eq!(
            convert_intent_from_string("NIFTI_INTENT_TRIANGLE").unwrap(),
            Intent::Triangle
        );
        assert_eq!(
            convert_intent_from_string("NIFTI_INTENT_SHAPE").unwrap(),
            Intent::Shape
        );
    }

    #[test]
    fn test_convert_endian() {
        assert_eq!(convert_endian("BigEndian").unwrap(), Endianness::BigEndian);
        assert_eq!(convert_endian("LittleEndian").unwrap(), Endianness::LittleEndian);
    }

    #[test]
    fn test_convert_binary_datatype() {
        let info = convert_binary_datatype(DataType::UInt8);
        assert_eq!(info.size_bytes, 1);
        assert!(!info.signed);
        assert!(!info.floating_point);
        assert_eq!(info.name, "UINT8");

        let info = convert_binary_datatype(DataType::Float32);
        assert_eq!(info.size_bytes, 4);
        assert!(info.signed);
        assert!(info.floating_point);
        assert_eq!(info.name, "FLOAT32");
    }

    #[test]
    fn test_datatype_checks() {
        assert!(is_integer_datatype(DataType::UInt8));
        assert!(is_integer_datatype(DataType::Int32));
        assert!(!is_integer_datatype(DataType::Float32));

        assert!(is_float_datatype(DataType::Float32));
        assert!(!is_float_datatype(DataType::UInt8));

        assert!(is_signed_datatype(DataType::Int32));
        assert!(is_signed_datatype(DataType::Float32));
        assert!(!is_signed_datatype(DataType::UInt8));

        assert!(is_unsigned_datatype(DataType::UInt8));
        assert!(is_unsigned_datatype(DataType::UInt32));
        assert!(!is_unsigned_datatype(DataType::Int32));
    }

    #[test]
    fn test_encoding_checks() {
        assert!(requires_external_file(Encoding::ExternalFileBinary));
        assert!(!requires_external_file(Encoding::Ascii));

        assert!(uses_compression(Encoding::GZipBase64Binary));
        assert!(!uses_compression(Encoding::Base64Binary));

        assert!(uses_base64(Encoding::Base64Binary));
        assert!(uses_base64(Encoding::GZipBase64Binary));
        assert!(!uses_base64(Encoding::Ascii));

        assert!(is_text_encoding(Encoding::Ascii));
        assert!(!is_text_encoding(Encoding::Base64Binary));

        assert!(is_binary_encoding(Encoding::Base64Binary));
        assert!(!is_binary_encoding(Encoding::Ascii));
    }

    #[test]
    fn test_endian_conversion() {
        assert!(!needs_endian_conversion(Endianness::BigEndian, Endianness::BigEndian));
        assert!(needs_endian_conversion(Endianness::BigEndian, Endianness::LittleEndian));

        let value = 0x12345678u32;
        let converted = convert_endian_value(value, Endianness::BigEndian, Endianness::LittleEndian);
        assert_eq!(converted, 0x78563412u32);

        let unchanged = convert_endian_value(value, Endianness::BigEndian, Endianness::BigEndian);
        assert_eq!(unchanged, value);
    }
}

