        assert!(is_signed_datatype(DataType::Int32));
        assert!(is_signed_datatype(DataType::Float32));
        assert!(!is_signed_datatype(DataType::UInt8));

        assert!(is_unsigned_datatype(DataType::UInt8));
        assert!(is_unsigned_datatype(DataType::UInt32));
        assert!(!is_unsigned_datatype(DataType::Int32));
    }

    #[test]
    fn test_encoding_checks() {
        assert!(requires_external_file(Encoding::ExternalFileBinary));
        assert!(!requires_external_file(Encoding::Ascii));

        assert!(uses_compression(Encoding::GZipBase64Binary));
        assert!(!uses_compression(Encoding::Base64Binary));

        assert!(uses_base64(Encoding::Base64Binary));
        assert!(uses_base64(Encoding::GZipBase64Binary));
        assert!(!uses_base64(Encoding::Ascii));

        assert!(is_text_encoding(Encoding::Ascii));
        assert!(!is_text_encoding(Encoding::Base64Binary));

        assert!(is_binary_encoding(Encoding::Base64Binary));
        assert!(!is_binary_encoding(Encoding::Ascii));
    }

    #[test]
    fn test_endian_conversion() {
        assert!(!needs_endian_conversion(Endianness::BigEndian, Endianness::BigEndian));
        assert!(needs_endian_conversion(Endianness::BigEndian, Endianness::LittleEndian));

        let value = 0x12345678u32;
        let converted = convert_endian_value(value, Endianness::BigEndian, Endianness::LittleEndian);
        assert_eq!(converted, 0x78563412u32);

        let unchanged = convert_endian_value(value, Endianness::BigEndian, Endianness::BigEndian);
        assert_eq!(unchanged, value);
    }
}

