//! Surface processing utilities for GIFTI files
//!
//! This module provides functions for working with surface data in GIFTI files,
//! including triangle extraction and coordinate mapping.

use crate::core::data_array::DataArray;
use crate::core::gifti::Gifti;
use crate::core::types::Intent;
use crate::error::{GiftiError, Result};
use ndarray::{Array1, Array2};

/// Surface triangle data extracted from GIFTI files
#[derive(Debug, Clone, PartialEq)]
pub struct SurfaceTriangles {
    /// 3D coordinates of vertices (N × 3)
    pub pointset: Array2<f64>,
    /// Triangle connectivity (M × 3, indices into pointset)
    pub triangle: Array2<i32>,
}

impl SurfaceTriangles {
    /// Create new surface triangles
    pub fn new(pointset: Array2<f64>, triangle: Array2<i32>) -> Result<Self> {
        // Validate pointset dimensions
        if pointset.ncols() != 3 {
            return Err(GiftiError::validation_error(
                "Pointset must have 3 columns (x, y, z coordinates)".to_string(),
            ));
        }

        // Validate triangle dimensions
        if triangle.ncols() != 3 {
            return Err(GiftiError::validation_error(
                "Triangle array must have 3 columns (vertex indices)".to_string(),
            ));
        }

        // Validate triangle indices
        let num_vertices = pointset.nrows();
        for &index in triangle.iter() {
            if index < 0 || index >= num_vertices as i32 {
                return Err(GiftiError::validation_error(format!(
                    "Triangle index {} is out of range [0, {})",
                    index, num_vertices
                )));
            }
        }

        Ok(Self { pointset, triangle })
    }

    /// Get the number of vertices
    pub fn num_vertices(&self) -> usize {
        self.pointset.nrows()
    }

    /// Get the number of triangles
    pub fn num_triangles(&self) -> usize {
        self.triangle.nrows()
    }

    /// Get a specific vertex coordinate
    pub fn vertex(&self, index: usize) -> Result<[f64; 3]> {
        if index >= self.num_vertices() {
            return Err(GiftiError::index_out_of_bounds(index));
        }

        let row = self.pointset.row(index);
        Ok([row[0], row[1], row[2]])
    }

    /// Get a specific triangle
    pub fn triangle_indices(&self, index: usize) -> Result<[i32; 3]> {
        if index >= self.num_triangles() {
            return Err(GiftiError::index_out_of_bounds(index));
        }

        let row = self.triangle.row(index);
        Ok([row[0], row[1], row[2]])
    }

    /// Get triangle vertex coordinates
    pub fn triangle_vertices(&self, index: usize) -> Result<[[f64; 3]; 3]> {
        let indices = self.triangle_indices(index)?;
        Ok([
            self.vertex(indices[0] as usize)?,
            self.vertex(indices[1] as usize)?,
            self.vertex(indices[2] as usize)?,
        ])
    }

    /// Calculate the centroid of all vertices
    pub fn centroid(&self) -> [f64; 3] {
        let mean_x = self.pointset.column(0).mean().unwrap_or(0.0);
        let mean_y = self.pointset.column(1).mean().unwrap_or(0.0);
        let mean_z = self.pointset.column(2).mean().unwrap_or(0.0);
        [mean_x, mean_y, mean_z]
    }

    /// Calculate the bounding box of all vertices
    pub fn bounding_box(&self) -> ([f64; 3], [f64; 3]) {
        let mut min_coords = [f64::INFINITY; 3];
        let mut max_coords = [f64::NEG_INFINITY; 3];

        for i in 0..self.num_vertices() {
            let vertex = self.vertex(i).unwrap();
            for j in 0..3 {
                min_coords[j] = min_coords[j].min(vertex[j]);
                max_coords[j] = max_coords[j].max(vertex[j]);
            }
        }

        (min_coords, max_coords)
    }

    /// Calculate the surface area of a triangle
    pub fn triangle_area(&self, index: usize) -> Result<f64> {
        let vertices = self.triangle_vertices(index)?;
        let v1 = vertices[0];
        let v2 = vertices[1];
        let v3 = vertices[2];

        // Calculate vectors from v1 to v2 and v1 to v3
        let vec1 = [v2[0] - v1[0], v2[1] - v1[1], v2[2] - v1[2]];
        let vec2 = [v3[0] - v1[0], v3[1] - v1[1], v3[2] - v1[2]];

        // Calculate cross product
        let cross = [
            vec1[1] * vec2[2] - vec1[2] * vec2[1],
            vec1[2] * vec2[0] - vec1[0] * vec2[2],
            vec1[0] * vec2[1] - vec1[1] * vec2[0],
        ];

        // Calculate magnitude of cross product
        let magnitude = (cross[0] * cross[0] + cross[1] * cross[1] + cross[2] * cross[2]).sqrt();

        // Area is half the magnitude of the cross product
        Ok(magnitude / 2.0)
    }

    /// Calculate the total surface area
    pub fn total_surface_area(&self) -> f64 {
        let mut total_area = 0.0;
        for i in 0..self.num_triangles() {
            if let Ok(area) = self.triangle_area(i) {
                total_area += area;
            }
        }
        total_area
    }

    /// Reorder vertices based on triangles (matching R behavior)
    pub fn reorder_vertices(&self) -> Array2<f64> {
        let mut reordered = Array2::zeros((self.num_triangles() * 3, 3));

        for (tri_idx, triangle_row) in self.triangle.outer_iter().enumerate() {
            for (vert_idx, &vertex_index) in triangle_row.iter().enumerate() {
                let vertex = self.pointset.row(vertex_index as usize);
                reordered.row_mut(tri_idx * 3 + vert_idx).assign(&vertex);
            }
        }

        reordered
    }
}

/// Extract surface triangles from a GIFTI file
/// 
/// This function matches the behavior of the R `surf_triangles` function,
/// extracting pointset and triangle data from a GIFTI file.
pub fn surf_triangles(gifti: &Gifti) -> Result<SurfaceTriangles> {
    // Get pointset data
    let pointset_array = gifti.get_pointset().ok_or_else(|| {
        GiftiError::missing_element("No pointset data found in GIFTI file")
    })?;

    // Get triangle data
    let triangle_array = gifti.get_triangles().ok_or_else(|| {
        GiftiError::missing_element("No triangle data found in GIFTI file")
    })?;

    // Extract pointset data
    let pointset_data = pointset_array.as_2d().map_err(|_| {
        GiftiError::validation_error("Pointset data must be 2D".to_string())
    })?;

    // Extract triangle data
    let triangle_data = triangle_array.as_2d().map_err(|_| {
        GiftiError::validation_error("Triangle data must be 2D".to_string())
    })?;

    // Convert triangle data to i32 (R uses 1-based indexing, we convert to 0-based)
    let triangle_i32 = triangle_data.mapv(|x| x as i32);

    // In R, indices are 1-based, so we need to subtract 1 for 0-based indexing
    let triangle_corrected = triangle_i32.mapv(|x| x - 1);

    SurfaceTriangles::new(pointset_data, triangle_corrected)
}

/// Map values to triangular mesh coordinates
/// 
/// This function matches the behavior of the R `gifti_map_value` function,
/// mapping scalar values to triangle vertices.
pub fn gifti_map_value(
    triangles: &SurfaceTriangles,
    values: &Array1<f64>,
) -> Result<Array1<f64>> {
    let num_vertices = triangles.num_vertices();

    // Validate that we have the right number of values
    if values.len() != num_vertices {
        return Err(GiftiError::dimension_mismatch(num_vertices, values.len()));
    }

    // Create output array with values mapped to triangle vertices
    let mut mapped_values = Array1::zeros(triangles.num_triangles() * 3);

    for (tri_idx, triangle_row) in triangles.triangle.outer_iter().enumerate() {
        for (vert_idx, &vertex_index) in triangle_row.iter().enumerate() {
            let value = values[vertex_index as usize];
            mapped_values[tri_idx * 3 + vert_idx] = value;
        }
    }

    Ok(mapped_values)
}

/// Calculate vertex normals for a surface
pub fn calculate_vertex_normals(triangles: &SurfaceTriangles) -> Result<Array2<f64>> {
    let num_vertices = triangles.num_vertices();
    let mut normals = Array2::zeros((num_vertices, 3));
    let mut vertex_triangle_count = vec![0; num_vertices];

    // Calculate face normals and accumulate at vertices
    for tri_idx in 0..triangles.num_triangles() {
        let triangle_indices = triangles.triangle_indices(tri_idx)?;
        let vertices = triangles.triangle_vertices(tri_idx)?;

        // Calculate face normal using cross product
        let v1 = vertices[0];
        let v2 = vertices[1];
        let v3 = vertices[2];

        let vec1 = [v2[0] - v1[0], v2[1] - v1[1], v2[2] - v1[2]];
        let vec2 = [v3[0] - v1[0], v3[1] - v1[1], v3[2] - v1[2]];

        let normal = [
            vec1[1] * vec2[2] - vec1[2] * vec2[1],
            vec1[2] * vec2[0] - vec1[0] * vec2[2],
            vec1[0] * vec2[1] - vec1[1] * vec2[0],
        ];

        // Normalize the face normal
        let magnitude = (normal[0] * normal[0] + normal[1] * normal[1] + normal[2] * normal[2]).sqrt();
        let normalized_normal = if magnitude > 0.0 {
            [normal[0] / magnitude, normal[1] / magnitude, normal[2] / magnitude]
        } else {
            [0.0, 0.0, 0.0]
        };

        // Accumulate normal at each vertex of the triangle
        for &vertex_index in &triangle_indices {
            let vertex_idx = vertex_index as usize;
            normals[[vertex_idx, 0]] += normalized_normal[0];
            normals[[vertex_idx, 1]] += normalized_normal[1];
            normals[[vertex_idx, 2]] += normalized_normal[2];
            vertex_triangle_count[vertex_idx] += 1;
        }
    }

    // Average the normals and normalize
    for vertex_idx in 0..num_vertices {
        if vertex_triangle_count[vertex_idx] > 0 {
            let count = vertex_triangle_count[vertex_idx] as f64;
            normals[[vertex_idx, 0]] /= count;
            normals[[vertex_idx, 1]] /= count;
            normals[[vertex_idx, 2]] /= count;

            // Normalize the resulting normal
            let magnitude = (normals[[vertex_idx, 0]] * normals[[vertex_idx, 0]]
                + normals[[vertex_idx, 1]] * normals[[vertex_idx, 1]]
                + normals[[vertex_idx, 2]] * normals[[vertex_idx, 2]])
                .sqrt();

            if magnitude > 0.0 {
                normals[[vertex_idx, 0]] /= magnitude;
                normals[[vertex_idx, 1]] /= magnitude;
                normals[[vertex_idx, 2]] /= magnitude;
            }
        }
    }

    Ok(normals)
}

/// Validate surface topology
pub fn validate_surface_topology(triangles: &SurfaceTriangles) -> Result<SurfaceTopologyInfo> {
    let num_vertices = triangles.num_vertices();
    let num_triangles = triangles.num_triangles();

    // Check for duplicate vertices
    let mut duplicate_vertices = 0;
    for i in 0..num_vertices {
        for j in (i + 1)..num_vertices {
            let v1 = triangles.vertex(i)?;
            let v2 = triangles.vertex(j)?;
            if (v1[0] - v2[0]).abs() < f64::EPSILON
                && (v1[1] - v2[1]).abs() < f64::EPSILON
                && (v1[2] - v2[2]).abs() < f64::EPSILON
            {
                duplicate_vertices += 1;
            }
        }
    }

    // Check for degenerate triangles
    let mut degenerate_triangles = 0;
    for i in 0..num_triangles {
        if let Ok(area) = triangles.triangle_area(i) {
            if area < f64::EPSILON {
                degenerate_triangles += 1;
            }
        }
    }

    // Check for unused vertices
    let mut used_vertices = vec![false; num_vertices];
    for triangle_row in triangles.triangle.outer_iter() {
        for &vertex_index in triangle_row.iter() {
            if vertex_index >= 0 && (vertex_index as usize) < num_vertices {
                used_vertices[vertex_index as usize] = true;
            }
        }
    }
    let unused_vertices = used_vertices.iter().filter(|&&used| !used).count();

    // Calculate Euler characteristic (V - E + F = 2 for a closed surface)
    let mut edge_count = 0;
    let mut edges = std::collections::HashSet::new();

    for triangle_row in triangles.triangle.outer_iter() {
        let indices = [triangle_row[0], triangle_row[1], triangle_row[2]];
        for i in 0..3 {
            let v1 = indices[i];
            let v2 = indices[(i + 1) % 3];
            let edge = if v1 < v2 { (v1, v2) } else { (v2, v1) };
            edges.insert(edge);
        }
    }
    edge_count = edges.len();

    let euler_characteristic = num_vertices as i32 - edge_count as i32 + num_triangles as i32;

    Ok(SurfaceTopologyInfo {
        num_vertices,
        num_triangles,
        num_edges: edge_count,
        duplicate_vertices,
        degenerate_triangles,
        unused_vertices,
        euler_characteristic,
        is_closed_surface: euler_characteristic == 2,
    })
}

/// Information about surface topology
#[derive(Debug, Clone, PartialEq)]
pub struct SurfaceTopologyInfo {
    pub num_vertices: usize,
    pub num_triangles: usize,
    pub num_edges: usize,
    pub duplicate_vertices: usize,
    pub degenerate_triangles: usize,
    pub unused_vertices: usize,
    pub euler_characteristic: i32,
    pub is_closed_surface: bool,
}

impl std::fmt::Display for SurfaceTopologyInfo {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        writeln!(f, "Surface Topology Information:")?;
        writeln!(f, "  Vertices: {}", self.num_vertices)?;
        writeln!(f, "  Triangles: {}", self.num_triangles)?;
        writeln!(f, "  Edges: {}", self.num_edges)?;
        writeln!(f, "  Duplicate Vertices: {}", self.duplicate_vertices)?;
        writeln!(f, "  Degenerate Triangles: {}", self.degenerate_triangles)?;
        writeln!(f, "  Unused Vertices: {}", self.unused_vertices)?;
        writeln!(f, "  Euler Characteristic: {}", self.euler_characteristic)?;
        writeln!(f, "  Closed Surface: {}", self.is_closed_surface)?;
        Ok(())
    }
}

