//! Validation utilities for GIFTI files
//!
//! This module provides functions for validating GIFTI files and data structures,
//! including the `is_gifti` function that matches the R package behavior.

use crate::core::gifti::Gifti;
use crate::error::Result;
use std::path::Path;

/// Check if a given object is a valid GIFTI structure
/// 
/// This function matches the behavior of the R `is.gifti` function,
/// validating that the provided structure is a valid GIFTI object.
pub fn is_gifti(gifti: &Gifti) -> bool {
    // Validate the GIFTI structure
    match gifti.validate() {
        Ok(_) => true,
        Err(_) => false,
    }
}

/// Check if a file is a valid GIFTI file
pub fn is_gifti_file<P: AsRef<Path>>(path: P) -> bool {
    crate::io::reader::is_gifti_file(path)
}

/// Validate a GIFTI file and return detailed validation results
pub fn validate_gifti_file<P: AsRef<Path>>(path: P) -> Result<GiftiValidationReport> {
    let gifti = crate::io::reader::read_gifti(path)?;
    validate_gifti_structure(&gifti)
}

/// Validate a GIFTI structure and return detailed validation results
pub fn validate_gifti_structure(gifti: &Gifti) -> Result<GiftiValidationReport> {
    let mut report = GiftiValidationReport::new();

    // Validate basic structure
    if gifti.version.is_empty() {
        report.add_error("GIFTI version is empty".to_string());
    } else {
        report.add_info(format!("GIFTI version: {}", gifti.version));
    }

    if gifti.data_arrays.is_empty() {
        report.add_error("No data arrays found".to_string());
    } else {
        report.add_info(format!("Number of data arrays: {}", gifti.data_arrays.len()));
    }

    // Validate each data array
    for (i, array) in gifti.data_arrays.iter().enumerate() {
        match array.validate() {
            Ok(_) => {
                report.add_info(format!("Data array {} is valid", i));
            }
            Err(e) => {
                report.add_error(format!("Data array {} validation failed: {}", i, e));
            }
        }

        // Check data array specific properties
        if array.is_empty() {
            report.add_warning(format!("Data array {} is empty", i));
        }

        if array.attributes.dimensions.iter().any(|&d| d == 0) {
            report.add_error(format!("Data array {} has zero-sized dimension", i));
        }
    }

    // Validate label table if present
    if let Some(label_table) = &gifti.label_table {
        match label_table.validate() {
            Ok(_) => {
                report.add_info(format!("Label table is valid with {} labels", label_table.len()));
            }
            Err(e) => {
                report.add_error(format!("Label table validation failed: {}", e));
            }
        }
    }

    // Validate surface consistency
    if gifti.is_surface() {
        match validate_surface_consistency(gifti) {
            Ok(surface_info) => {
                report.add_info(format!("Surface validation passed: {}", surface_info));
            }
            Err(e) => {
                report.add_error(format!("Surface validation failed: {}", e));
            }
        }
    }

    // Validate metadata
    if gifti.metadata.is_empty() {
        report.add_warning("No file metadata found".to_string());
    } else {
        report.add_info(format!("File metadata entries: {}", gifti.metadata.len()));
    }

    // Overall validation
    match gifti.validate() {
        Ok(_) => {
            report.add_info("Overall GIFTI validation passed".to_string());
        }
        Err(e) => {
            report.add_error(format!("Overall GIFTI validation failed: {}", e));
        }
    }

    Ok(report)
}

/// Validate surface consistency
fn validate_surface_consistency(gifti: &Gifti) -> Result<String> {
    let pointset = gifti.get_pointset().ok_or_else(|| {
        crate::error::GiftiError::missing_element("Pointset data not found")
    })?;

    let triangles = gifti.get_triangles().ok_or_else(|| {
        crate::error::GiftiError::missing_element("Triangle data not found")
    })?;

    let num_vertices = pointset.shape()[0];
    let num_triangles = triangles.len() / 3; // Assuming triangles are stored flat

    // Check pointset dimensions
    if pointset.shape().len() != 2 || pointset.shape()[1] != 3 {
        return Err(crate::error::GiftiError::validation_error(
            "Pointset must be N×3 (vertices × coordinates)".to_string(),
        ));
    }

    // Check triangle dimensions
    if triangles.shape().len() != 2 || triangles.shape()[1] != 3 {
        return Err(crate::error::GiftiError::validation_error(
            "Triangle array must be M×3 (triangles × vertex indices)".to_string(),
        ));
    }

    // Check triangle indices
    let triangle_data = triangles.as_flat();
    for &index in &triangle_data {
        let vertex_index = index as usize;
        if vertex_index >= num_vertices {
            return Err(crate::error::GiftiError::validation_error(format!(
                "Triangle vertex index {} exceeds number of vertices {}",
                vertex_index, num_vertices
            )));
        }
    }

    Ok(format!(
        "Surface has {} vertices and {} triangles",
        num_vertices, num_triangles
    ))
}

/// Detailed validation report for GIFTI files
#[derive(Debug, Clone)]
pub struct GiftiValidationReport {
    pub errors: Vec<String>,
    pub warnings: Vec<String>,
    pub info: Vec<String>,
}

impl GiftiValidationReport {
    pub fn new() -> Self {
        Self {
            errors: Vec::new(),
            warnings: Vec::new(),
            info: Vec::new(),
        }
    }

    pub fn add_error(&mut self, message: String) {
        self.errors.push(message);
    }

    pub fn add_warning(&mut self, message: String) {
        self.warnings.push(message);
    }

    pub fn add_info(&mut self, message: String) {
        self.info.push(message);
    }

    pub fn is_valid(&self) -> bool {
        self.errors.is_empty()
    }

    pub fn has_warnings(&self) -> bool {
        !self.warnings.is_empty()
    }

    pub fn has_errors(&self) -> bool {
        !self.errors.is_empty()
    }

    pub fn summary(&self) -> String {
        format!(
            "Validation Report: {} errors, {} warnings, {} info messages",
            self.errors.len(),
            self.warnings.len(),
            self.info.len()
        )
    }
}

impl Default for GiftiValidationReport {
    fn default() -> Self {
        Self::new()
    }
}

impl std::fmt::Display for GiftiValidationReport {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        writeln!(f, "GIFTI Validation Report")?;
        writeln!(f, "======================")?;

        if !self.errors.is_empty() {
            writeln!(f, "\nErrors:")?;
            for error in &self.errors {
                writeln!(f, "  ❌ {}", error)?;
            }
        }

        if !self.warnings.is_empty() {
            writeln!(f, "\nWarnings:")?;
            for warning in &self.warnings {
                writeln!(f, "  ⚠️  {}", warning)?;
            }
        }

        if !self.info.is_empty() {
            writeln!(f, "\nInfo:")?;
            for info in &self.info {
                writeln!(f, "  ℹ️  {}", info)?;
            }
        }

        writeln!(f, "\nSummary: {}", self.summary())?;

        if self.is_valid() {
            writeln!(f, "✅ GIFTI file is valid")?;
        } else {
            writeln!(f, "❌ GIFTI file has validation errors")?;
        }

        Ok(())
    }
}

/// Quick validation check for common GIFTI issues
pub fn quick_validate(gifti: &Gifti) -> Vec<String> {
    let mut issues = Vec::new();

    // Check basic structure
    if gifti.version.is_empty() {
        issues.push("Missing GIFTI version".to_string());
    }

    if gifti.data_arrays.is_empty() {
        issues.push("No data arrays found".to_string());
    }

    // Check data arrays
    for (i, array) in gifti.data_arrays.iter().enumerate() {
        if array.is_empty() {
            issues.push(format!("Data array {} is empty", i));
        }

        if array.attributes.dimensions.iter().any(|&d| d == 0) {
            issues.push(format!("Data array {} has zero-sized dimension", i));
        }
    }

    // Check surface consistency
    if gifti.is_surface() {
        if let (Some(pointset), Some(triangles)) = (gifti.get_pointset(), gifti.get_triangles()) {
            let num_vertices = pointset.shape()[0];
            let triangle_data = triangles.as_flat();

            for &index in &triangle_data {
                let vertex_index = index as usize;
                if vertex_index >= num_vertices {
                    issues.push(format!(
                        "Triangle vertex index {} exceeds number of vertices {}",
                        vertex_index, num_vertices
                    ));
                    break; // Don't spam with too many similar errors
                }
            }
        }
    }

    issues
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::core::data_array::DataArray;
    use crate::core::gifti::Gifti;
    use crate::core::types::{DataType, Encoding, Intent};

    #[test]
    fn test_is_gifti_valid() {
        let mut gifti = Gifti::new();

        // Add a valid data array
        let data_array = DataArray::new_1d(
            vec![1.0, 2.0, 3.0],
            DataType::Float32,
            Encoding::Ascii,
            Intent::Shape,
        ).unwrap();

