//! Data array structures for GIFTI files
//!
//! This module contains the `DataArray` struct and related types that represent
//! the core data storage units in GIFTI files.

use crate::core::metadata::{CoordinateSystemTransform, MetaData};
use crate::core::types::{ArrayIndexingOrder, DataType, Encoding, Endianness, Intent};
use crate::error::{GiftiError, Result};
use ndarray::{Array1, Array2, ArrayD, Dimension, IxDyn};
use serde::{Deserialize, Serialize};

/// Attributes for a GIFTI data array
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct DataArrayAttributes {
    /// Data type of the array elements
    pub data_type: DataType,
    /// Encoding format of the data
    pub encoding: Encoding,
    /// Byte order for binary data
    pub endianness: Endianness,
    /// Intent/purpose of the data
    pub intent: Intent,
    /// Number of dimensions
    pub dimensionality: usize,
    /// Size of each dimension
    pub dimensions: Vec<usize>,
    /// Array indexing order
    pub indexing_order: ArrayIndexingOrder,
    /// External file name (if applicable)
    pub external_filename: Option<String>,
    /// External file offset (if applicable)
    pub external_file_offset: Option<u64>,
}

impl DataArrayAttributes {
    /// Create new data array attributes
    pub fn new(
        data_type: DataType,
        encoding: Encoding,
        endianness: Endianness,
        intent: Intent,
        dimensions: Vec<usize>,
        indexing_order: ArrayIndexingOrder,
    ) -> Self {
        let dimensionality = dimensions.len();
        Self {
            data_type,
            encoding,
            endianness,
            intent,
            dimensionality,
            dimensions,
            indexing_order,
            external_filename: None,
            external_file_offset: None,
        }
    }

    /// Get the total number of elements
    pub fn num_elements(&self) -> usize {
        self.dimensions.iter().product()
    }

    /// Get the size in bytes for all elements
    pub fn size_bytes(&self) -> usize {
        self.num_elements() * self.data_type.size_bytes()
    }

    /// Validate the attributes
    pub fn validate(&self) -> Result<()> {
        if self.dimensionality != self.dimensions.len() {
            return Err(GiftiError::validation_error(format!(
                "Dimensionality {} does not match dimensions length {}",
                self.dimensionality,
                self.dimensions.len()
            )));
        }

        if self.dimensions.is_empty() {
            return Err(GiftiError::validation_error(
                "Dimensions cannot be empty".to_string(),
            ));
        }

        for (i, &dim) in self.dimensions.iter().enumerate() {
            if dim == 0 {
                return Err(GiftiError::validation_error(format!(
                    "Dimension {} cannot be zero",
                    i
                )));
            }
        }

        // Validate external file settings
        if matches!(self.encoding, Encoding::ExternalFileBinary) {
            if self.external_filename.is_none() {
                return Err(GiftiError::validation_error(
                    "External filename required for ExternalFileBinary encoding".to_string(),
                ));
            }
        }

        Ok(())
    }

    /// Check if this is a 1D array
    pub fn is_1d(&self) -> bool {
        self.dimensionality == 1
    }

    /// Check if this is a 2D array
    pub fn is_2d(&self) -> bool {
        self.dimensionality == 2
    }

    /// Check if this is a vector (1D array)
    pub fn is_vector(&self) -> bool {
        self.is_1d()
    }

    /// Check if this is a matrix (2D array)
    pub fn is_matrix(&self) -> bool {
        self.is_2d()
    }

    /// Get the shape as a tuple for 1D arrays
    pub fn shape_1d(&self) -> Result<usize> {
        if !self.is_1d() {
            return Err(GiftiError::validation_error(format!(
                "Array is not 1D, has {} dimensions",
                self.dimensionality
            )));
        }
        Ok(self.dimensions[0])
    }

    /// Get the shape as a tuple for 2D arrays
    pub fn shape_2d(&self) -> Result<(usize, usize)> {
        if !self.is_2d() {
            return Err(GiftiError::validation_error(format!(
                "Array is not 2D, has {} dimensions",
                self.dimensionality
            )));
        }
        Ok((self.dimensions[0], self.dimensions[1]))
    }
}

/// GIFTI data array containing numeric data and metadata
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct DataArray {
    /// Array attributes
    pub attributes: DataArrayAttributes,
    /// Data array metadata
    pub metadata: MetaData,
    /// Coordinate system transformations
    pub transformations: Vec<CoordinateSystemTransform>,
    /// The actual data as a dynamic n-dimensional array
    pub data: ArrayD<f64>,
}

impl DataArray {
    /// Create a new data array with 1D data
    pub fn new_1d(
        data: Vec<f64>,
        data_type: DataType,
        encoding: Encoding,
        intent: Intent,
    ) -> Result<Self> {
        let len = data.len();
        let dimensions = vec![len];
        let attributes = DataArrayAttributes::new(
            data_type,
            encoding,
            Endianness::native(),
            intent,
            dimensions,
            ArrayIndexingOrder::RowMajor,
        );

        let data_array = Array1::from_vec(data).into_dyn();

        Ok(Self {
            attributes,
            metadata: MetaData::new(),
            transformations: Vec::new(),
            data: data_array,
        })
    }

    /// Create a new data array with 2D data
    pub fn new_2d(
        data: Vec<f64>,
        shape: (usize, usize),
        data_type: DataType,
        encoding: Encoding,
        intent: Intent,
        indexing_order: ArrayIndexingOrder,
    ) -> Result<Self> {
        let dimensions = vec![shape.0, shape.1];
        let attributes = DataArrayAttributes::new(
            data_type,
            encoding,
            Endianness::native(),
            intent,
            dimensions,
            indexing_order,
        );

        if data.len() != shape.0 * shape.1 {
            return Err(GiftiError::dimension_mismatch(shape.0 * shape.1, data.len()));
        }

        let data_array = match indexing_order {
            ArrayIndexingOrder::RowMajor => {
                Array2::from_shape_vec((shape.0, shape.1), data)?.into_dyn()
            }
            ArrayIndexingOrder::ColumnMajor => {
                Array2::from_shape_vec((shape.0, shape.1).f(), data)?.into_dyn()
            }
        };

        Ok(Self {
            attributes,
            metadata: MetaData::new(),
            transformations: Vec::new(),
            data: data_array,
        })
    }

    /// Create a new data array with n-dimensional data
    pub fn new_nd(
        data: Vec<f64>,
        dimensions: Vec<usize>,
        data_type: DataType,
        encoding: Encoding,
        intent: Intent,
        indexing_order: ArrayIndexingOrder,
    ) -> Result<Self> {
        let attributes = DataArrayAttributes::new(
            data_type,
            encoding,
            Endianness::native(),
            intent,
            dimensions.clone(),
            indexing_order,
        );

        let expected_len: usize = dimensions.iter().product();
        if data.len() != expected_len {
            return Err(GiftiError::dimension_mismatch(expected_len, data.len()));
        }

        let shape = IxDyn(&dimensions);
        let data_array = ArrayD::from_shape_vec(shape, data)?;

        Ok(Self {
            attributes,
            metadata: MetaData::new(),
            transformations: Vec::new(),
            data: data_array,
        })
    }

    /// Get the data as a 1D array
    pub fn as_1d(&self) -> Result<Array1<f64>> {
        if !self.attributes.is_1d() {
            return Err(GiftiError::validation_error(format!(
                "Array is not 1D, has {} dimensions",
                self.attributes.dimensionality
            )));
        }
        Ok(self.data.clone().into_dimensionality::<ndarray::Ix1>()?)
    }

    /// Get the data as a 2D array
    pub fn as_2d(&self) -> Result<Array2<f64>> {
        if !self.attributes.is_2d() {
            return Err(GiftiError::validation_error(format!(
                "Array is not 2D, has {} dimensions",
                self.attributes.dimensionality
            )));
        }
        Ok(self.data.clone().into_dimensionality::<ndarray::Ix2>()?)
    }

    /// Get the data as a flat vector
    pub fn as_flat(&self) -> Vec<f64> {
        self.data.iter().copied().collect()
    }

    /// Get the shape of the data array
    pub fn shape(&self) -> &[usize] {
        self.data.shape()
    }

    /// Get the number of dimensions
    pub fn ndim(&self) -> usize {
        self.data.ndim()
    }

    /// Get the number of elements
    pub fn len(&self) -> usize {
        self.data.len()
    }

    /// Check if the array is empty
    pub fn is_empty(&self) -> bool {
        self.data.is_empty()
    }

    /// Add metadata
    pub fn add_metadata(&mut self, key: String, value: String) {
        self.metadata.insert(key, value);
    }

    /// Add a coordinate system transformation
    pub fn add_transformation(&mut self, transform: CoordinateSystemTransform) {
        self.transformations.push(transform);
    }

    /// Get the intent name
    pub fn intent_name(&self) -> &'static str {
        self.attributes.intent.name()
    }

    /// Validate the data array
    pub fn validate(&self) -> Result<()> {
        self.attributes.validate()?;

        // Check that data dimensions match attributes
        if self.data.shape() != self.attributes.dimensions.as_slice() {
            return Err(GiftiError::validation_error(format!(
                "Data shape {:?} does not match attributes dimensions {:?}",
                self.data.shape(),
                self.attributes.dimensions
            )));
        }

        // Validate transformations
        for transform in &self.transformations {
            if !transform.is_invertible() {
                log::warn!(
                    "Transformation matrix from {} to {} is not invertible",
                    transform.data_space,
                    transform.transformed_space
                );
            }
        }

        Ok(())
    }

    /// Check if this data array represents pointset data
    pub fn is_pointset(&self) -> bool {
        matches!(self.attributes.intent, Intent::Pointset)
    }

    /// Check if this data array represents triangle data
    pub fn is_triangle(&self) -> bool {
        matches!(self.attributes.intent, Intent::Triangle)
    }

    /// Check if this data array represents shape data
    pub fn is_shape(&self) -> bool {
        matches!(self.attributes.intent, Intent::Shape)
    }

    /// Check if this data array represents time series data
    pub fn is_timeseries(&self) -> bool {
        matches!(self.attributes.intent, Intent::TimeSeries)
    }

    /// Check if this data array represents label data
    pub fn is_label(&self) -> bool {
        matches!(self.attributes.intent, Intent::Label)
    }
}

// Implement conversion from ndarray errors
impl From<ndarray::ShapeError> for GiftiError {
    fn from(err: ndarray::ShapeError) -> Self {
        GiftiError::validation_error(format!("Array shape error: {}", err))
    }
}

