//! Main GIFTI structure and implementation
//!
//! This module contains the main `Gifti` struct that represents a complete
//! GIFTI file with all its data arrays, metadata, and label tables.

use crate::core::data_array::DataArray;
use crate::core::metadata::{LabelTable, MetaData};
use crate::core::types::Intent;
use crate::error::{GiftiError, Result};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;

/// Main GIFTI structure representing a complete GIFTI file
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct Gifti {
    /// GIFTI format version
    pub version: String,
    /// File-level metadata
    pub metadata: MetaData,
    /// Label table for categorical data
    pub label_table: Option<LabelTable>,
    /// Data arrays contained in the file
    pub data_arrays: Vec<DataArray>,
}

impl Gifti {
    /// Create a new empty GIFTI structure
    pub fn new() -> Self {
        Self {
            version: "1.0".to_string(),
            metadata: MetaData::new(),
            label_table: None,
            data_arrays: Vec::new(),
        }
    }

    /// Create a new GIFTI structure with specified version
    pub fn with_version(version: String) -> Self {
        Self {
            version,
            metadata: MetaData::new(),
            label_table: None,
            data_arrays: Vec::new(),
        }
    }

    /// Add a data array to the GIFTI file
    pub fn add_data_array(&mut self, data_array: DataArray) {
        self.data_arrays.push(data_array);
    }

    /// Get the number of data arrays
    pub fn num_data_arrays(&self) -> usize {
        self.data_arrays.len()
    }

    /// Get a data array by index
    pub fn get_data_array(&self, index: usize) -> Option<&DataArray> {
        self.data_arrays.get(index)
    }

    /// Get a mutable reference to a data array by index
    pub fn get_data_array_mut(&mut self, index: usize) -> Option<&mut DataArray> {
        self.data_arrays.get_mut(index)
    }

    /// Get data arrays by intent
    pub fn get_data_arrays_by_intent(&self, intent: Intent) -> Vec<&DataArray> {
        self.data_arrays
            .iter()
            .filter(|array| array.attributes.intent == intent)
            .collect()
    }

    /// Get the first data array with the specified intent
    pub fn get_first_data_array_by_intent(&self, intent: Intent) -> Option<&DataArray> {
