            version: self.version.clone(),
            num_data_arrays: self.data_arrays.len(),
            has_metadata: !self.metadata.is_empty(),
            has_label_table: self.label_table.is_some(),
            intent_counts,
            is_surface: self.is_surface(),
            is_shape_file: self.is_shape_file(),
            is_timeseries_file: self.is_timeseries_file(),
            is_label_file: self.is_label_file(),
        }
    }

    /// Validate the entire GIFTI structure
    pub fn validate(&self) -> Result<()> {
        // Validate version
        if self.version.is_empty() {
            return Err(GiftiError::validation_error(
