//! Metadata structures for GIFTI files
//!
//! This module contains structures for handling metadata in GIFTI files,
//! including file-level metadata, data array metadata, and label tables.

use crate::error::{GiftiError, Result};
use indexmap::IndexMap;
use serde::{Deserialize, Serialize};
use std::collections::HashMap;

/// Metadata key-value pairs
#[derive(Debug, Clone, PartialEq)]
pub struct MetaData {
    /// Ordered map of metadata key-value pairs
    pub data: IndexMap<String, String>,
}

impl MetaData {
    /// Create a new empty metadata collection
    pub fn new() -> Self {
        Self {
            data: IndexMap::new(),
        }
    }

    /// Create metadata from a vector of key-value pairs
    pub fn from_pairs(pairs: Vec<(String, String)>) -> Self {
        let mut data = IndexMap::new();
        for (key, value) in pairs {
            data.insert(key, value);
        }
        Self { data }
    }

    /// Insert a key-value pair
    pub fn insert(&mut self, key: String, value: String) {
        self.data.insert(key, value);
    }

    /// Get a value by key
    pub fn get(&self, key: &str) -> Option<&String> {
        self.data.get(key)
    }

    /// Check if metadata is empty
    pub fn is_empty(&self) -> bool {
        self.data.is_empty()
    }

    /// Get the number of metadata entries
    pub fn len(&self) -> usize {
        self.data.len()
    }

    /// Iterate over key-value pairs
    pub fn iter(&self) -> impl Iterator<Item = (&String, &String)> {
        self.data.iter()
    }

    /// Get all keys
    pub fn keys(&self) -> impl Iterator<Item = &String> {
        self.data.keys()
    }

    /// Get all values
    pub fn values(&self) -> impl Iterator<Item = &String> {
        self.data.values()
    }
}

impl Default for MetaData {
    fn default() -> Self {
        Self::new()
    }
}

impl From<IndexMap<String, String>> for MetaData {
    fn from(data: IndexMap<String, String>) -> Self {
        Self { data }
    }
}

impl From<HashMap<String, String>> for MetaData {
    fn from(map: HashMap<String, String>) -> Self {
        let mut data = IndexMap::new();
        for (key, value) in map {
            data.insert(key, value);
        }
        Self { data }
    }
}

/// Label table entry for categorical data
#[derive(Debug, Clone, PartialEq)]
pub struct Label {
    /// Unique identifier for the label
    pub index: u32,
    /// Label text/name
    pub text: String,
    /// Red color component (0.0-1.0)
    pub red: f32,
    /// Green color component (0.0-1.0)
    pub green: f32,
    /// Blue color component (0.0-1.0)
    pub blue: f32,
    /// Alpha/transparency component (0.0-1.0)
    pub alpha: f32,
}

impl Label {
    /// Create a new label
    pub fn new(index: u32, text: String, red: f32, green: f32, blue: f32, alpha: f32) -> Self {
        Self {
            index,
            text,
            red,
            green,
            blue,
            alpha,
        }
    }

    /// Create a label with default white color
    pub fn with_text(index: u32, text: String) -> Self {
        Self::new(index, text, 1.0, 1.0, 1.0, 1.0)
    }

    /// Get the RGB color as a tuple
    pub fn rgb(&self) -> (f32, f32, f32) {
        (self.red, self.green, self.blue)
    }

    /// Get the RGBA color as a tuple
    pub fn rgba(&self) -> (f32, f32, f32, f32) {
        (self.red, self.green, self.blue, self.alpha)
    }

    /// Set the RGB color
    pub fn set_rgb(&mut self, red: f32, green: f32, blue: f32) {
        self.red = red;
        self.green = green;
        self.blue = blue;
    }

    /// Set the RGBA color
    pub fn set_rgba(&mut self, red: f32, green: f32, blue: f32, alpha: f32) {
        self.red = red;
        self.green = green;
        self.blue = blue;
        self.alpha = alpha;
    }

    /// Validate color components (should be 0.0-1.0)
    pub fn validate_colors(&self) -> Result<()> {
        let check_range = |value: f32, name: &str| {
            if !(0.0..=1.0).contains(&value) {
                return Err(GiftiError::validation_error(format!(
                    "Color component {} must be between 0.0 and 1.0, got {}",
                    name, value
                )));
            }
            Ok(())
        };

        check_range(self.red, "red")?;
        check_range(self.green, "green")?;
        check_range(self.blue, "blue")?;
        check_range(self.alpha, "alpha")?;

        Ok(())
    }
}

/// Label table containing all labels for categorical data
#[derive(Debug, Clone, PartialEq)]
pub struct LabelTable {
    /// Map from label index to label data
    pub labels: IndexMap<u32, Label>,
}

impl LabelTable {
    /// Create a new empty label table
    pub fn new() -> Self {
        Self {
