        self.labels.get_mut(&index)
    }

    /// Remove a label by index
    pub fn remove_label(&mut self, index: u32) -> Option<Label> {
        self.labels.shift_remove(&index)
    }

    /// Check if the table is empty
    pub fn is_empty(&self) -> bool {
        self.labels.is_empty()
    }

    /// Get the number of labels
    pub fn len(&self) -> usize {
        self.labels.len()
    }

    /// Iterate over all labels
    pub fn iter(&self) -> impl Iterator<Item = (&u32, &Label)> {
        self.labels.iter()
    }

    /// Get all label indices
    pub fn indices(&self) -> impl Iterator<Item = &u32> {
        self.labels.keys()
    }

    /// Get all labels
    pub fn labels(&self) -> impl Iterator<Item = &Label> {
        self.labels.values()
    }

    /// Validate all labels in the table
    pub fn validate(&self) -> Result<()> {
        for label in self.labels.values() {
            label.validate_colors()?;
        }
        Ok(())
    }

    /// Get the maximum label index
    pub fn max_index(&self) -> Option<u32> {
        self.labels.keys().max().copied()
    }

    /// Get the minimum label index
    pub fn min_index(&self) -> Option<u32> {
        self.labels.keys().min().copied()
    }

    /// Check if a label index exists
    pub fn contains_index(&self, index: u32) -> bool {
        self.labels.contains_key(&index)
    }

    /// Get a label by text (first match)
    pub fn get_label_by_text(&self, text: &str) -> Option<&Label> {
        self.labels.values().find(|label| label.text == text)
    }

    /// Get all labels with a specific text
    pub fn get_labels_by_text(&self, text: &str) -> Vec<&Label> {
        self.labels
            .values()
            .filter(|label| label.text == text)
            .collect()
    }
}

impl Default for LabelTable {
    fn default() -> Self {
        Self::new()
    }
}

impl From<Vec<Label>> for LabelTable {
    fn from(labels: Vec<Label>) -> Self {
        let mut table = Self::new();
        for label in labels {
            table.add_label(label);
        }
        table
    }
}

