    ConnDenseTime,
    /// Functional connectivity parcellated
    ConnParcellated,
    /// Functional connectivity parcellated time
    ConnParcellatedTime,
    /// Functional connectivity trajectory
    ConnTrajectory,
    /// Functional connectivity trajectory time
    ConnTrajectoryTime,
    /// Shape data
    Shape,
    /// Normal vectors
    Normal,
    /// Curvature data
    Curvature,
    /// Arbitrary scalar data
    Scalar,
    /// Time series data
    TimeSeries,
    /// RGB color data
    RgbVector,
    /// RGBA color data
    RgbaVector,
    /// Label data
    Label,
    /// Generic data
    Generic,
}

impl Intent {
    /// Convert to NIFTI intent string
    pub fn to_nifti_string(&self) -> &'static str {
        match self {
            Intent::None => "NIFTI_INTENT_NONE",
            Intent::Pointset => "NIFTI_INTENT_POINTSET",
            Intent::Triangle => "NIFTI_INTENT_TRIANGLE",
            Intent::Quaternion => "NIFTI_INTENT_QUATERNION",
            Intent::NewMeshVertices => "NIFTI_INTENT_NEW_MESH_VERTICES",
            Intent::ConnDense => "NIFTI_INTENT_CONN_DENSE",
            Intent::ConnDenseTime => "NIFTI_INTENT_CONN_DENSE_TIME",
            Intent::ConnParcellated => "NIFTI_INTENT_CONN_PARCELLATED",
            Intent::ConnParcellatedTime => "NIFTI_INTENT_CONN_PARCELLATED_TIME",
            Intent::ConnTrajectory => "NIFTI_INTENT_CONN_TRAJECTORY",
            Intent::ConnTrajectoryTime => "NIFTI_INTENT_CONN_TRAJECTORY_TIME",
            Intent::Shape => "NIFTI_INTENT_SHAPE",
            Intent::Normal => "NIFTI_INTENT_NORMAL",
            Intent::Curvature => "NIFTI_INTENT_CURVATURE",
            Intent::Scalar => "NIFTI_INTENT_SCALAR",
