use serde::{Deserialize, Serialize};
use std::fmt;
use std::str::FromStr;

/// GIFTI data types corresponding to NIFTI data types
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum DataType {
    /// Unsigned 8-bit integer
    UInt8,
    /// Signed 32-bit integer
    Int32,
    /// Unsigned 32-bit integer
    UInt32,
    /// 32-bit floating point
    Float32,
}

impl DataType {
    /// Get the size in bytes for this data type
    pub fn size_bytes(&self) -> usize {
        match self {
            DataType::UInt8 => 1,
            DataType::Int32 => 4,
            DataType::UInt32 => 4,
            DataType::Float32 => 4,
        }
    }

    /// Convert to NIFTI type string
    pub fn to_nifti_string(&self) -> &'static str {
        match self {
            DataType::UInt8 => "NIFTI_TYPE_UINT8",
            DataType::Int32 => "NIFTI_TYPE_INT32",
            DataType::UInt32 => "NIFTI_TYPE_UINT32",
            DataType::Float32 => "NIFTI_TYPE_FLOAT32",
        }
    }

    /// Create from NIFTI type string
    pub fn from_nifti_string(s: &str) -> Result<Self> {
        match s {
            "NIFTI_TYPE_UINT8" => Ok(DataType::UInt8),
            "NIFTI_TYPE_INT32" => Ok(DataType::Int32),
            "NIFTI_TYPE_UINT32" => Ok(DataType::UInt32),
            "NIFTI_TYPE_FLOAT32" => Ok(DataType::Float32),
            _ => Err(GiftiError::unsupported_data_type(s)),
        }
    }
}

impl fmt::Display for DataType {
