//! Data array structures for GIFTI files
//!
//! This module contains simplified data array structures for GIFTI files.

use crate::core::metadata::{MetaData};
use crate::core::types::{DataType, Encoding, Endianness, Intent};
use crate::error::{GiftiError, Result};

/// Simplified attributes for a GIFTI data array
#[derive(Debug, Clone, PartialEq)]
pub struct DataArrayAttributes {
    /// Data type of the array elements
    pub data_type: DataType,
    /// Encoding format of the data
    pub encoding: Encoding,
    /// Byte order for binary data
    pub endianness: Endianness,
    /// Intent/purpose of the data
    pub intent: Intent,
    /// Size of each dimension
    pub dimensions: Vec<usize>,
}

impl DataArrayAttributes {
    /// Create new data array attributes
    pub fn new(
        data_type: DataType,
        encoding: Encoding,
        endianness: Endianness,
        intent: Intent,
        dimensions: Vec<usize>,
    ) -> Self {
        Self {
            data_type,
            encoding,
            endianness,
            intent,
            dimensions,
        }
    }

    /// Get the total number of elements
    pub fn num_elements(&self) -> usize {
        self.dimensions.iter().product()
    }

    /// Get the size in bytes for all elements
    pub fn size_bytes(&self) -> usize {
        self.num_elements() * self.data_type.size_bytes()
    }

    /// Validate the attributes
    pub fn validate(&self) -> Result<()> {
        if self.dimensions.is_empty() {
            return Err(GiftiError::validation_error(
                "Dimensions cannot be empty".to_string(),
            ));
        }

        for (i, &dim) in self.dimensions.iter().enumerate() {
            if dim == 0 {
                return Err(GiftiError::validation_error(format!(
                    "Dimension {} cannot be zero",
                    i
                )));
            }
        }

        Ok(())
    }

    /// Check if this is a 1D array
    pub fn is_1d(&self) -> bool {
        self.dimensions.len() == 1
    }

    /// Check if this is a 2D array
    pub fn is_2d(&self) -> bool {
        self.dimensions.len() == 2
    }
}

/// Simplified GIFTI data array
#[derive(Debug, Clone, PartialEq)]
pub struct DataArray {
    /// Array attributes
    pub attributes: DataArrayAttributes,
    /// Data array metadata
    pub metadata: MetaData,
    /// The actual data as a flat vector
    pub data: Vec<f64>,
}

impl DataArray {
    /// Create a new data array with 1D data
    pub fn new_1d(
        data: Vec<f64>,
        data_type: DataType,
        encoding: Encoding,
        intent: Intent,
    ) -> Result<Self> {
        let len = data.len();
        let dimensions = vec![len];
        let attributes = DataArrayAttributes::new(
            data_type,
            encoding,
            Endianness::native(),
            intent,
            dimensions,
        );

        Ok(Self {
            attributes,
            metadata: MetaData::new(),
            data,
        })
    }

    /// Get the data as a flat vector
    pub fn as_flat(&self) -> Vec<f64> {
        self.data.clone()
    }

    /// Get the shape of the data array
    pub fn shape(&self) -> &[usize] {
        &self.attributes.dimensions
    }

    /// Get the number of dimensions
    pub fn ndim(&self) -> usize {
        self.attributes.dimensions.len()
    }

    /// Get the number of elements
    pub fn len(&self) -> usize {
        self.data.len()
    }

    /// Check if the array is empty
    pub fn is_empty(&self) -> bool {
        self.data.is_empty()
    }

    /// Add metadata
    pub fn add_metadata(&mut self, key: String, value: String) {
        self.metadata.insert(key, value);
    }

    /// Get the intent name
    pub fn intent_name(&self) -> &'static str {
        self.attributes.intent.name()
    }

    /// Validate the data array
    pub fn validate(&self) -> Result<()> {
        self.attributes.validate()?;

        // Check that data length matches expected size
        let expected_len = self.attributes.num_elements();
        if self.data.len() != expected_len {
            return Err(GiftiError::validation_error(format!(
                "Data length {} does not match expected size {}",
                self.data.len(),
                expected_len
            )));
        }

        Ok(())
    }

    /// Check if this data array represents pointset data
    pub fn is_pointset(&self) -> bool {
        matches!(self.attributes.intent, Intent::Pointset)
    }

    /// Check if this data array represents triangle data
    pub fn is_triangle(&self) -> bool {
        matches!(self.attributes.intent, Intent::Triangle)
    }

    /// Check if this data array represents shape data
    pub fn is_shape(&self) -> bool {
        matches!(self.attributes.intent, Intent::Shape)
    }

    /// Check if this data array represents time series data
    pub fn is_timeseries(&self) -> bool {
        matches!(self.attributes.intent, Intent::TimeSeries)
    }

    /// Check if this data array represents label data
    pub fn is_label(&self) -> bool {
        matches!(self.attributes.intent, Intent::Label)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_data_array_creation() {
        let data = vec![1.0, 2.0, 3.0];
        let array = DataArray::new_1d(
            data.clone(),
            DataType::Float32,
            Encoding::Ascii,
            Intent::Shape,
        ).unwrap();

        assert_eq!(array.len(), 3);
        assert_eq!(array.as_flat(), data);
        assert!(array.is_shape());
        assert!(!array.is_pointset());
    }

    #[test]
    fn test_data_array_attributes() {
        let attrs = DataArrayAttributes::new(
            DataType::Float32,
            Encoding::Ascii,
            Endianness::native(),
            Intent::Shape,
            vec![3, 3],
        );

        assert_eq!(attrs.num_elements(), 9);
        assert_eq!(attrs.size_bytes(), 36); // 9 * 4 bytes per float32
        assert!(attrs.is_2d());
        assert!(!attrs.is_1d());
    }

    #[test]
    fn test_data_array_validation() {
        let data = vec![1.0, 2.0, 3.0];
        let array = DataArray::new_1d(
            data,
            DataType::Float32,
            Encoding::Ascii,
            Intent::Shape,
        ).unwrap();

        assert!(array.validate().is_ok());
    }
}

