    40→            version,
    41→            metadata: MetaData::new(),
    42→            label_table: None,
    43→            data_arrays: Vec::new(),
    44→        }
    45→    }
    46→
    47→    /// Add a data array to the GIFTI file
    48→    pub fn add_data_array(&mut self, data_array: DataArray) {
    49→        self.data_arrays.push(data_array);
    50→    }
    51→
    52→    /// Get the number of data arrays
    53→    pub fn num_data_arrays(&self) -> usize {
    54→        self.data_arrays.len()
    55→    }
    56→
    57→    /// Get a data array by index
