    59→        self.data_arrays.get(index)
    60→    }
    61→
    62→    /// Get a mutable reference to a data array by index
    63→    pub fn get_data_array_mut(&mut self, index: usize) -> Option<&mut DataArray> {
    64→        self.data_arrays.get_mut(index)
    65→    }
    66→
    67→    /// Get data arrays by intent
    68→    pub fn get_data_arrays_by_intent(&self, intent: Intent) -> Vec<&DataArray> {
    69→        self.data_arrays
    70→            .iter()
    71→            .filter(|array| array.attributes.intent == intent)
    72→            .collect()
    73→    }
    74→
    75→    /// Get the first data array with the specified intent
    76→    pub fn get_first_data_array_by_intent(&self, intent: Intent) -> Option<&DataArray> {
    77→        self.data_arrays
    78→            .iter()
    79→            .find(|array| array.attributes.intent == intent)
    80→    }
    81→
    82→    /// Add file-level metadata
    83→    pub fn add_metadata(&mut self, key: String, value: String) {
    84→        self.metadata.insert(key, value);
    85→    }
    86→
    87→    /// Get file-level metadata
    88→    pub fn get_metadata(&self, key: &str) -> Option<&String> {
    89→        self.metadata.get(key)
    90→    }
    91→
    92→    /// Set the label table
    93→    pub fn set_label_table(&mut self, label_table: LabelTable) {
    94→        self.label_table = Some(label_table);
    95→    }
    96→
    97→    /// Get the label table
    98→    pub fn get_label_table(&self) -> Option<&LabelTable> {
    99→        self.label_table.as_ref()
   100→    }
   101→
   102→    /// Get a mutable reference to the label table
   103→    pub fn get_label_table_mut(&mut self) -> Option<&mut LabelTable> {
   104→        self.label_table.as_mut()
   105→    }
   106→
   107→    /// Check if this GIFTI file contains pointset data
   108→    pub fn has_pointset(&self) -> bool {
   109→        self.data_arrays.iter().any(|array| array.is_pointset())
   110→    }
   111→
   112→    /// Check if this GIFTI file contains triangle data
   113→    pub fn has_triangles(&self) -> bool {
   114→        self.data_arrays.iter().any(|array| array.is_triangle())
   115→    }
   116→
   117→    /// Check if this GIFTI file contains shape data
   118→    pub fn has_shape(&self) -> bool {
   119→        self.data_arrays.iter().any(|array| array.is_shape())
   120→    }
   121→
   122→    /// Check if this GIFTI file contains time series data
   123→    pub fn has_timeseries(&self) -> bool {
   124→        self.data_arrays.iter().any(|array| array.is_timeseries())
   125→    }
   126→
   127→    /// Check if this GIFTI file contains label data
   128→    pub fn has_labels(&self) -> bool {
   129→        self.data_arrays.iter().any(|array| array.is_label())
   130→    }
   131→
   132→    /// Get pointset data (vertices)
   133→    pub fn get_pointset(&self) -> Option<&DataArray> {
   134→        self.get_first_data_array_by_intent(Intent::Pointset)
   135→    }
   136→
   137→    /// Get triangle data (connectivity)
   138→    pub fn get_triangles(&self) -> Option<&DataArray> {
   139→        self.get_first_data_array_by_intent(Intent::Triangle)
   140→    }
   141→
   142→    /// Get shape data
   143→    pub fn get_shape(&self) -> Option<&DataArray> {
   144→        self.get_first_data_array_by_intent(Intent::Shape)
   145→    }
   146→
   147→    /// Get time series data arrays
   148→    pub fn get_timeseries(&self) -> Vec<&DataArray> {
   149→        self.get_data_arrays_by_intent(Intent::TimeSeries)
   150→    }
   151→
   152→    /// Get label data
   153→    pub fn get_labels(&self) -> Option<&DataArray> {
   154→        self.get_first_data_array_by_intent(Intent::Label)
   155→    }
   156→
   157→    /// Check if this is a surface file (has both pointset and triangles)
   158→    pub fn is_surface(&self) -> bool {
   159→        self.has_pointset() && self.has_triangles()
   160→    }
   161→
   162→    /// Check if this is a shape file (has shape data)
   163→    pub fn is_shape_file(&self) -> bool {
   164→        self.has_shape()
   165→    }
   166→
   167→    /// Check if this is a time series file (has time series data)
   168→    pub fn is_timeseries_file(&self) -> bool {
   169→        self.has_timeseries()
   170→    }
   171→
   172→    /// Check if this is a label file (has label data and label table)
   173→    pub fn is_label_file(&self) -> bool {
   174→        self.has_labels() && self.label_table.is_some()
   175→    }
   176→
   177→    /// Get surface data as pointset and triangles
   178→    pub fn get_surface_data(&self) -> Option<(&DataArray, &DataArray)> {
   179→        if let (Some(pointset), Some(triangles)) = (self.get_pointset(), self.get_triangles()) {
   180→            Some((pointset, triangles))
   181→        } else {
   182→            None
   183→        }
   184→    }
   185→
   186→    /// Get a summary of the GIFTI file contents
   187→    pub fn summary(&self) -> GiftiSummary {
   188→        let mut intent_counts = HashMap::new();
   189→        for array in &self.data_arrays {
   190→            *intent_counts.entry(array.attributes.intent).or_insert(0) += 1;
   191→        }
   192→
   193→        GiftiSummary {
   194→            version: self.version.clone(),
   195→            num_data_arrays: self.data_arrays.len(),
   196→            has_metadata: !self.metadata.is_empty(),
   197→            has_label_table: self.label_table.is_some(),
   198→            intent_counts,
   199→            is_surface: self.is_surface(),
   200→            is_shape_file: self.is_shape_file(),
   201→            is_timeseries_file: self.is_timeseries_file(),
   202→            is_label_file: self.is_label_file(),
   203→        }
   204→    }
   205→
   206→    /// Validate the entire GIFTI structure
   207→    pub fn validate(&self) -> Result<()> {
   208→        // Validate version
   209→        if self.version.is_empty() {
   210→            return Err(GiftiError::validation_error(
   211→                "GIFTI version cannot be empty".to_string(),
