    10→
    11→/// GIFTI data types corresponding to NIFTI data types
    12→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
    13→pub enum DataType {
    14→    /// Unsigned 8-bit integer
    15→    UInt8,
    16→    /// Signed 32-bit integer
    17→    Int32,
    18→    /// Unsigned 32-bit integer
    19→    UInt32,
    20→    /// 32-bit floating point
    21→    Float32,
    22→}
    23→
    24→impl DataType {
    25→    /// Get the size in bytes for this data type
    26→    pub fn size_bytes(&self) -> usize {
    27→        match self {
    28→            DataType::UInt8 => 1,
    29→            DataType::Int32 => 4,
    30→            DataType::UInt32 => 4,
    31→            DataType::Float32 => 4,
    32→        }
    33→    }
    34→
    35→    /// Convert to NIFTI type string
    36→    pub fn to_nifti_string(&self) -> &'static str {
    37→        match self {
    38→            DataType::UInt8 => "NIFTI_TYPE_UINT8",
    39→            DataType::Int32 => "NIFTI_TYPE_INT32",
    40→            DataType::UInt32 => "NIFTI_TYPE_UINT32",
    41→            DataType::Float32 => "NIFTI_TYPE_FLOAT32",
    42→        }
    43→    }
    44→
    45→    /// Create from NIFTI type string
    46→    pub fn from_nifti_string(s: &str) -> Result<Self> {
    47→        match s {
    48→            "NIFTI_TYPE_UINT8" => Ok(DataType::UInt8),
    49→            "NIFTI_TYPE_INT32" => Ok(DataType::Int32),
    50→            "NIFTI_TYPE_UINT32" => Ok(DataType::UInt32),
    51→            "NIFTI_TYPE_FLOAT32" => Ok(DataType::Float32),
    52→            _ => Err(GiftiError::unsupported_data_type(s)),
    53→        }
    54→    }
    55→}
    56→
    57→impl fmt::Display for DataType {
    58→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
    59→        write!(f, "{}", self.to_nifti_string())
    60→    }
    61→}
    62→
    63→impl FromStr for DataType {
    64→    type Err = GiftiError;
    65→
    66→    fn from_str(s: &str) -> Result<Self> {
    67→        Self::from_nifti_string(s)
    68→    }
    69→}
    70→
    71→/// Data encoding formats supported by GIFTI
    72→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
    73→pub enum Encoding {
    74→    /// ASCII text encoding
    75→    Ascii,
    76→    /// Base64 binary encoding
    77→    Base64Binary,
    78→    /// GZip compressed Base64 binary encoding
    79→    GZipBase64Binary,
    80→    /// External file binary encoding
    81→    ExternalFileBinary,
    82→}
    83→
    84→impl Encoding {
    85→    /// Convert to GIFTI encoding string
    86→    pub fn to_gifti_string(&self) -> &'static str {
    87→        match self {
    88→            Encoding::Ascii => "ASCII",
    89→            Encoding::Base64Binary => "Base64Binary",
    90→            Encoding::GZipBase64Binary => "GZipBase64Binary",
    91→            Encoding::ExternalFileBinary => "ExternalFileBinary",
    92→        }
    93→    }
    94→
    95→    /// Create from GIFTI encoding string
    96→    pub fn from_gifti_string(s: &str) -> Result<Self> {
    97→        match s {
    98→            "ASCII" => Ok(Encoding::Ascii),
    99→            "Base64Binary" => Ok(Encoding::Base64Binary),
   100→            "GZipBase64Binary" => Ok(Encoding::GZipBase64Binary),
   101→            "ExternalFileBinary" => Ok(Encoding::ExternalFileBinary),
   102→            _ => Err(GiftiError::unsupported_encoding(s)),
   103→        }
   104→    }
   105→}
   106→
   107→impl fmt::Display for Encoding {
   108→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
   109→        write!(f, "{}", self.to_gifti_string())
   110→    }
   111→}
   112→
   113→impl FromStr for Encoding {
   114→    type Err = GiftiError;
   115→
   116→    fn from_str(s: &str) -> Result<Self> {
   117→        Self::from_gifti_string(s)
   118→    }
   119→}
   120→
   121→/// Byte order (endianness) for binary data
   122→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
   123→pub enum Endianness {
   124→    /// Big endian byte order
   125→    BigEndian,
   126→    /// Little endian byte order
   127→    LittleEndian,
   128→}
   129→
   130→impl Endianness {
   131→    /// Convert to GIFTI endianness string
   132→    pub fn to_gifti_string(&self) -> &'static str {
   133→        match self {
   134→            Endianness::BigEndian => "BigEndian",
   135→            Endianness::LittleEndian => "LittleEndian",
   136→        }
   137→    }
   138→
   139→    /// Create from GIFTI endianness string
   140→    pub fn from_gifti_string(s: &str) -> Result<Self> {
   141→        match s {
   142→            "BigEndian" => Ok(Endianness::BigEndian),
   143→            "LittleEndian" => Ok(Endianness::LittleEndian),
   144→            _ => Err(GiftiError::invalid_endianness(s)),
   145→        }
   146→    }
   147→
   148→    /// Get the native endianness of the current system
   149→    pub fn native() -> Self {
