   170→}
   171→
   172→/// GIFTI intent codes (based on NIFTI intent codes)
   173→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
   174→pub enum Intent {
   175→    /// No specific intent
   176→    None,
   177→    /// Spatial coordinate data
   178→    Pointset,
   179→    /// Triangular mesh connectivity
   180→    Triangle,
   181→    /// Quaternion transformations
   182→    Quaternion,
   183→    /// New mesh vertices
   184→    NewMeshVertices,
   185→    /// Functional connectivity dense
   186→    ConnDense,
   187→    /// Functional connectivity dense time
   188→    ConnDenseTime,
   189→    /// Functional connectivity parcellated
   190→    ConnParcellated,
   191→    /// Functional connectivity parcellated time
   192→    ConnParcellatedTime,
   193→    /// Functional connectivity trajectory
   194→    ConnTrajectory,
   195→    /// Functional connectivity trajectory time
   196→    ConnTrajectoryTime,
   197→    /// Shape data
   198→    Shape,
   199→    /// Normal vectors
   200→    Normal,
   201→    /// Curvature data
   202→    Curvature,
   203→    /// Arbitrary scalar data
   204→    Scalar,
   205→    /// Time series data
   206→    TimeSeries,
   207→    /// RGB color data
   208→    RgbVector,
   209→    /// RGBA color data
   210→    RgbaVector,
   211→    /// Label data
   212→    Label,
   213→    /// Generic data
   214→    Generic,
   215→}
   216→
   217→impl Intent {
   218→    /// Convert to NIFTI intent string
   219→    pub fn to_nifti_string(&self) -> &'static str {
   220→        match self {
   221→            Intent::None => "NIFTI_INTENT_NONE",
   222→            Intent::Pointset => "NIFTI_INTENT_POINTSET",
   223→            Intent::Triangle => "NIFTI_INTENT_TRIANGLE",
   224→            Intent::Quaternion => "NIFTI_INTENT_QUATERNION",
   225→            Intent::NewMeshVertices => "NIFTI_INTENT_NEW_MESH_VERTICES",
   226→            Intent::ConnDense => "NIFTI_INTENT_CONN_DENSE",
   227→            Intent::ConnDenseTime => "NIFTI_INTENT_CONN_DENSE_TIME",
   228→            Intent::ConnParcellated => "NIFTI_INTENT_CONN_PARCELLATED",
   229→            Intent::ConnParcellatedTime => "NIFTI_INTENT_CONN_PARCELLATED_TIME",
   230→            Intent::ConnTrajectory => "NIFTI_INTENT_CONN_TRAJECTORY",
