//! GIFTI file reader implementation
//!
//! This module provides a complete reader for GIFTI files with XML parsing.

use crate::core::gifti::Gifti;
use crate::core::data_array::{DataArray, DataArrayAttributes};
use crate::core::types::{DataType, Encoding, Endianness, Intent};
use crate::core::metadata::MetaData;
use crate::error::{GiftiError, Result};
use std::path::Path;
use std::fs;
use quick_xml::Reader;
use quick_xml::events::Event;

/// Read a GIFTI file from a file path
pub fn read_gifti<P: AsRef<Path>>(path: P) -> Result<Gifti> {
    let path = path.as_ref();

    // Check if file exists
    if !path.exists() {
        return Err(GiftiError::external_file_not_found(
            path.to_string_lossy().to_string(),
        ));
    }

    // Read file content
    let content = fs::read_to_string(path)
        .map_err(|e| GiftiError::io_error(format!("Failed to read file: {}", e)))?;

    // Parse XML content
    read_gifti_from_string(&content)
}

/// Read a GIFTI file from a string
pub fn read_gifti_from_string(content: &str) -> Result<Gifti> {
    let mut reader = Reader::from_str(content);
    reader.trim_text(true);

    let mut gifti = Gifti::new();
    let mut buf = Vec::new();
    let mut current_data_array: Option<DataArray> = None;
    let mut current_metadata = MetaData::new();
    let mut in_data_array = false;
    let mut in_metadata = false;
    let mut data_content = String::new();

    loop {
        match reader.read_event_into(&mut buf) {
            Ok(Event::Start(ref e)) => {
                println!("Start tag: {:?}", String::from_utf8_lossy(e.name().as_ref()));
                match e.name().as_ref() {
                    b"GIFTI" => {
                        // Parse GIFTI root attributes
                        for attr in e.attributes() {
                            let attr = attr.map_err(|e| GiftiError::xml_parse_error(e.to_string()))?;
                            match attr.key.as_ref() {
                                b"Version" => {
                                    let version = String::from_utf8_lossy(&attr.value).to_string();
                                    gifti.version = version;
                                }
                                b"NumberOfDataArrays" => {
                                    let _num_arrays = String::from_utf8_lossy(&attr.value)
                                        .parse::<usize>()
                                        .map_err(|_| GiftiError::xml_parse_error("Invalid NumberOfDataArrays".to_string()))?;
                                    // Note: num_data_arrays is computed from the actual number of arrays
                                }
                                _ => {}
                            }
                        }
                    }
                    b"MetaData" => {
                        in_metadata = true;
                        current_metadata = MetaData::new();
                    }
                    b"MD" => {
                        if in_metadata {
                            // Parse metadata entry
                            let mut name = String::new();
                            let mut value = String::new();

                            for attr in e.attributes() {
                                let attr = attr.map_err(|e| GiftiError::xml_parse_error(e.to_string()))?;
                                match attr.key.as_ref() {
                                    b"Name" => name = String::from_utf8_lossy(&attr.value).to_string(),
                                    b"Value" => value = String::from_utf8_lossy(&attr.value).to_string(),
                                    _ => {}
                                }
                            }

                            if !name.is_empty() {
                                println!("Adding metadata: {} = {}", name, value);
                                current_metadata.insert(name, value);
                            }
                        }
                    }
                    b"DataArray" => {
                        in_data_array = true;

                        // Parse DataArray attributes
                        let mut data_type = DataType::Float32;
                        let mut encoding = Encoding::Ascii;
                        let mut endianness = Endianness::native();
                        let mut intent = Intent::None;
                        let mut dimensions = Vec::new();

                        for attr in e.attributes() {
                            let attr = attr.map_err(|e| GiftiError::xml_parse_error(e.to_string()))?;
                            let attr_value = String::from_utf8_lossy(&attr.value);

                            match attr.key.as_ref() {
                                b"DataType" => {
                                    data_type = match attr_value.as_ref() {
                                        "NIFTI_TYPE_UINT8" => DataType::UInt8,
                                        "NIFTI_TYPE_INT32" => DataType::Int32,
                                        "NIFTI_TYPE_UINT32" => DataType::UInt32,
                                        "NIFTI_TYPE_FLOAT32" => DataType::Float32,
                                        _ => DataType::Float32,
                                    };
                                }
                                b"Encoding" => {
                                    encoding = match attr_value.as_ref() {
                                        "ASCII" => Encoding::Ascii,
                                        "Base64Binary" => Encoding::Base64Binary,
                                        "GZipBase64Binary" => Encoding::GZipBase64Binary,
                                        "ExternalFileBinary" => Encoding::ExternalFileBinary,
                                        _ => Encoding::Ascii,
                                    };
                                }
                                b"Endian" => {
                                    endianness = match attr_value.as_ref() {
                                        "LittleEndian" => Endianness::LittleEndian,
                                        "BigEndian" => Endianness::BigEndian,
                                        _ => Endianness::native(),
                                    };
                                }
                                b"Intent" => {
                                    intent = match attr_value.as_ref() {
                                        "NIFTI_INTENT_POINTSET" => Intent::Pointset,
                                        "NIFTI_INTENT_TRIANGLE" => Intent::Triangle,
                                        "NIFTI_INTENT_SHAPE" => Intent::Shape,
                                        "NIFTI_INTENT_TIME_SERIES" => Intent::TimeSeries,
                                        "NIFTI_INTENT_LABEL" => Intent::Label,
                                        _ => Intent::None,
                                    };
                                }
                                b"Dimensionality" => {
                                    let dim_count = attr_value.parse::<usize>()
                                        .map_err(|_| GiftiError::xml_parse_error("Invalid Dimensionality".to_string()))?;
                                    dimensions = vec![1; dim_count];
                                }
                                b"Dim0" => {
                                    if dimensions.is_empty() { dimensions.push(1); }
                                    if let Ok(dim) = attr_value.parse::<usize>() {
                                        if dimensions.len() > 0 { dimensions[0] = dim; }
                                    }
                                }
                                b"Dim1" => {
                                    if dimensions.len() < 2 { dimensions.push(1); }
                                    if let Ok(dim) = attr_value.parse::<usize>() {
                                        if dimensions.len() > 1 { dimensions[1] = dim; }
                                    }
                                }
                                _ => {}
                            }
                        }

                        // Create DataArray with parsed attributes
                        let attributes = DataArrayAttributes::new(
                            data_type,
                            encoding,
                            endianness,
                            intent,
                            dimensions,
                        );

                        current_data_array = Some(DataArray {
                            attributes,
                            metadata: MetaData::new(),
                            data: Vec::new(),
                        });

                        data_content.clear();
                    }
                    b"Data" => {
                        // Start collecting data content
                        data_content.clear();
                    }
                    _ => {}
                }
            }
            Ok(Event::End(ref e)) => {
                match e.name().as_ref() {
                    b"MetaData" => {
                        in_metadata = false;
                        if in_data_array {
                            if let Some(ref mut da) = current_data_array {
                                da.metadata = current_metadata.clone();
                            }
                        } else {
                            gifti.metadata = current_metadata.clone();
                        }
                    }
                    b"DataArray" => {
                        in_data_array = false;
                        if let Some(mut da) = current_data_array.take() {
                            // Parse the collected data content
                            if !data_content.trim().is_empty() {
                                da.data = parse_data_content(&data_content, &da.attributes)?;
                            }
                            gifti.data_arrays.push(da);
                        }
                    }
                    b"Data" => {
                        // Data content collection is complete
                    }
                    _ => {}
                }
            }
            Ok(Event::Text(e)) => {
                let text = e.unescape().map_err(|e| GiftiError::xml_parse_error(e.to_string()))?;
                if in_data_array {
                    data_content.push_str(&text);
                }
            }
            Ok(Event::Eof) => break,
            Err(e) => return Err(GiftiError::xml_parse_error(e.to_string())),
            _ => {}
        }

        buf.clear();
    }

    Ok(gifti)
}

