#[cfg(test)]
mod tests {
    use super::*;
    use std::io::Write;
    use tempfile::NamedTempFile;

    #[test]
    fn test_read_gifti_from_string() {
        let xml_content = r#"<?xml version="1.0"?>
        <GIFTI Version="1.0" NumberOfDataArrays="1">
            <MetaData>
                <MD Name="source" Value="test" />
            </MetaData>
            <DataArray Intent="NIFTI_INTENT_SHAPE" DataType="NIFTI_TYPE_FLOAT32" 
                       Dimensionality="1" Dim0="3" Encoding="ASCII" Endian="LittleEndian">
                <Data>1.0 2.0 3.0</Data>
            </DataArray>
        </GIFTI>"#;

        let gifti = read_gifti_from_string(xml_content).unwrap();
        println!("Version: {}", gifti.version);
        println!("Metadata: {:?}", gifti.metadata);
        println!("Data arrays: {}", gifti.data_arrays.len());

        assert_eq!(gifti.version, "1.0");
        assert!(gifti.get_metadata("source").is_some());
        assert_eq!(gifti.get_metadata("source").unwrap(), "test");
        assert_eq!(gifti.data_arrays.len(), 1);
        assert_eq!(gifti.data_arrays[0].data, vec![1.0, 2.0, 3.0]);
    }

    #[test]
    fn test_is_gifti_file() {
        let mut temp_file = NamedTempFile::with_suffix(".gii").unwrap();
        temp_file.write_all(b"test").unwrap();

        assert!(is_gifti_file(temp_file.path()));

        let mut non_gifti = NamedTempFile::with_suffix(".txt").unwrap();
        non_gifti.write_all(b"test").unwrap();

        assert!(!is_gifti_file(non_gifti.path()));
    }
}

