/// Decode Base64 binary data
pub fn decode_base64(data: &str, data_type: DataType, expected_count: usize) -> Result<Vec<f64>> {
    // Remove whitespace and newlines
    let clean_data = data.chars().filter(|c| !c.is_whitespace()).collect::<String>();

    // Decode Base64
    let decoded_bytes = base64::decode(&clean_data)
        .map_err(|e| GiftiError::decode_error(format!("Base64 decode error: {}", e)))?;

    // Convert bytes to the appropriate data type
    let values = match data_type {
        DataType::UInt8 => {
            decoded_bytes.iter().map(|&b| b as f64).collect()
        }
        DataType::Int32 => {
            if decoded_bytes.len() % 4 != 0 {
                return Err(GiftiError::decode_error("Invalid byte count for Int32 data".to_string()));
            }
            decoded_bytes
                .chunks(4)
                .map(|chunk| {
                    let bytes = [chunk[0], chunk[1], chunk[2], chunk[3]];
                    i32::from_le_bytes(bytes) as f64
                })
                .collect()
        }
        DataType::UInt32 => {
            if decoded_bytes.len() % 4 != 0 {
                return Err(GiftiError::decode_error("Invalid byte count for UInt32 data".to_string()));
            }
            decoded_bytes
                .chunks(4)
                .map(|chunk| {
                    let bytes = [chunk[0], chunk[1], chunk[2], chunk[3]];
                    u32::from_le_bytes(bytes) as f64
                })
                .collect()
        }
        DataType::Float32 => {
            if decoded_bytes.len() % 4 != 0 {
                return Err(GiftiError::decode_error("Invalid byte count for Float32 data".to_string()));
            }
            decoded_bytes
                .chunks(4)
                .map(|chunk| {
                    let bytes = [chunk[0], chunk[1], chunk[2], chunk[3]];
                    f32::from_le_bytes(bytes) as f64
                })
                .collect()
        }
    };

    // Validate expected count
    if values.len() != expected_count {
        return Err(GiftiError::decode_error(format!(
            "Expected {} values, got {}",
            expected_count,
            values.len()
        )));
    }

    Ok(values)
}

