                                    intent = match attr_value.as_ref() {
                                        "NIFTI_INTENT_POINTSET" => Intent::Pointset,
                                        "NIFTI_INTENT_TRIANGLE" => Intent::Triangle,
                                        "NIFTI_INTENT_SHAPE" => Intent::Shape,
                                        "NIFTI_INTENT_TIME_SERIES" => Intent::TimeSeries,
                                        "NIFTI_INTENT_LABEL" => Intent::Label,
                                        _ => Intent::None,
                                    };
                                }
                                b"Dimensionality" => {
                                    let dim_count = attr_value.parse::<usize>()
                                        .map_err(|_| GiftiError::xml_parse_error("Invalid Dimensionality".to_string()))?;
                                    dimensions = vec![1; dim_count];
                                }
                                b"Dim0" => {
                                    if dimensions.is_empty() { dimensions.push(1); }
                                    if let Ok(dim) = attr_value.parse::<usize>() {
                                        if dimensions.len() > 0 { dimensions[0] = dim; }
                                    }
                                }
                                b"Dim1" => {
                                    if dimensions.len() < 2 { dimensions.push(1); }
                                    if let Ok(dim) = attr_value.parse::<usize>() {
                                        if dimensions.len() > 1 { dimensions[1] = dim; }
                                    }
                                }
                                _ => {}
                            }
                        }

                        // Create DataArray with parsed attributes
                        let attributes = DataArrayAttributes::new(
                            data_type,
                            encoding,
                            endianness,
                            intent,
                            dimensions,
                        );

                        current_data_array = Some(DataArray {
                            attributes,
                            metadata: MetaData::new(),
                            data: Vec::new(),
                        });

                        data_content.clear();
                    }
                    b"Data" => {
                        // Start collecting data content
                        data_content.clear();
                    }
                    _ => {}
                }
            }
            Ok(Event::Empty(ref e)) => {
                match e.name().as_ref() {
                    b"MD" => {
                        if in_metadata {
                            // Parse metadata entry
                            let mut name = String::new();
                            let mut value = String::new();

                            for attr in e.attributes() {
                                let attr = attr.map_err(|e| GiftiError::xml_parse_error(e.to_string()))?;
                                match attr.key.as_ref() {
                                    b"Name" => name = String::from_utf8_lossy(&attr.value).to_string(),
                                    b"Value" => value = String::from_utf8_lossy(&attr.value).to_string(),
                                    _ => {}
                                }
                            }

                            if !name.is_empty() {
                                current_metadata.insert(name, value);
                            }
                        }
                    }
                    _ => {}
                }
            }
            Ok(Event::End(ref e)) => {
                match e.name().as_ref() {
                    b"MetaData" => {
                        in_metadata = false;
                        if in_data_array {
                            if let Some(ref mut da) = current_data_array {
                                da.metadata = current_metadata.clone();
                            }
                        } else {
                            gifti.metadata = current_metadata.clone();
                        }
                    }
                    b"DataArray" => {
                        in_data_array = false;
                        if let Some(mut da) = current_data_array.take() {
                            // Parse the collected data content
                            if !data_content.trim().is_empty() {
                                da.data = parse_data_content(&data_content, &da.attributes)?;
                            }
                            gifti.data_arrays.push(da);
                        }
                    }
                    b"Data" => {
                        // Data content collection is complete
                    }
                    _ => {}
                }
            }
            Ok(Event::Text(e)) => {
                let text = e.unescape().map_err(|e| GiftiError::xml_parse_error(e.to_string()))?;
                if in_data_array {
                    data_content.push_str(&text);
                }
            }
            Ok(Event::Eof) => break,
            Err(e) => return Err(GiftiError::xml_parse_error(e.to_string())),
            _ => {}
        }

        buf.clear();
    }

    Ok(gifti)
}

/// Parse data content based on encoding
fn parse_data_content(content: &str, attributes: &DataArrayAttributes) -> Result<Vec<f64>> {
    match attributes.encoding {
        Encoding::Ascii => {
            // Parse ASCII data
            let mut data = Vec::new();
            for line in content.lines() {
                for value_str in line.split_whitespace() {
                    let value = value_str.parse::<f64>()
                        .map_err(|_| GiftiError::data_parse_error(format!("Invalid float value: {}", value_str)))?;
                    data.push(value);
                }
            }
            Ok(data)
        }
        Encoding::Base64Binary => {
            // For now, return placeholder data
            // Full Base64 decoding would be implemented here
            Ok(vec![0.0; attributes.num_elements()])
        }
        Encoding::GZipBase64Binary => {
            // For now, return placeholder data
            // Full GZip + Base64 decoding would be implemented here
            Ok(vec![0.0; attributes.num_elements()])
        }
        Encoding::ExternalFileBinary => {
            // For now, return placeholder data
            // External file reading would be implemented here
            Ok(vec![0.0; attributes.num_elements()])
        }
    }
}

/// Check if a file is a valid GIFTI file
pub fn is_gifti_file<P: AsRef<Path>>(path: P) -> bool {
    let path = path.as_ref();

    // Simple check - look for .gii extension
    path.extension()
        .and_then(|ext| ext.to_str())
        .map(|ext| ext.to_lowercase() == "gii")
        .unwrap_or(false)
}

