//! Data encoding utilities for GIFTI files
//!
//! This module provides functions to encode data for various GIFTI encoding
//! formats including ASCII, Base64Binary, GZipBase64Binary, and ExternalFileBinary.

use crate::core::types::{DataType, Encoding, Endianness};
use crate::error::{GiftiError, Result};
use base64::{engine::general_purpose, Engine as _};
use byteorder::{BigEndian, LittleEndian, WriteBytesExt};
use flate2::write::GzEncoder;
use std::io::Write;

/// Encode data for a GIFTI data array
pub fn encode_data(
    data: &[f64],
    encoding: Encoding,
    data_type: DataType,
    endianness: Endianness,
) -> Result<String> {
    match encoding {
        Encoding::Ascii => encode_ascii(data),
        Encoding::Base64Binary => encode_base64_binary(data, data_type, endianness),
        Encoding::GZipBase64Binary => encode_gzip_base64_binary(data, data_type, endianness),
        Encoding::ExternalFileBinary => {
            Err(GiftiError::encode_error("ExternalFileBinary encoding not supported for string output"))
        }
    }
}

/// Encode data as ASCII text
fn encode_ascii(data: &[f64]) -> Result<String> {
    let mut result = String::new();

    for (i, &value) in data.iter().enumerate() {
        if i > 0 {
            result.push(' ');
        }
        result.push_str(&format!("{}", value));
    }

    Ok(result)
}

/// Encode data as Base64 binary
fn encode_base64_binary(data: &[f64], data_type: DataType, endianness: Endianness) -> Result<String> {
    let binary_data = encode_binary_data(data, data_type, endianness)?;
    Ok(general_purpose::STANDARD.encode(binary_data))
}

/// Encode data as GZip compressed Base64 binary
fn encode_gzip_base64_binary(data: &[f64], data_type: DataType, endianness: Endianness) -> Result<String> {
    let binary_data = encode_binary_data(data, data_type, endianness)?;

    // Compress with gzip
    let mut encoder = GzEncoder::new(Vec::new(), flate2::Compression::default());
    encoder.write_all(&binary_data).map_err(|e| {
        GiftiError::compression_error(format!("Failed to compress data: {}", e))
    })?;

    let compressed_data = encoder.finish().map_err(|e| {
        GiftiError::compression_error(format!("Failed to finish compression: {}", e))
    })?;

    Ok(general_purpose::STANDARD.encode(compressed_data))
}

/// Convert data to binary format based on data type and endianness
fn encode_binary_data(data: &[f64], data_type: DataType, endianness: Endianness) -> Result<Vec<u8>> {
    let mut buffer = Vec::new();

    match (data_type, endianness) {
        (DataType::UInt8, _) => {
            for &value in data {
                let byte_value = value.round() as u8;
                buffer.write_u8(byte_value).map_err(|e| {
                    GiftiError::encode_error(format!("Failed to write UINT8 value: {}", e))
                })?;
            }
        }
        (DataType::Int32, Endianness::BigEndian) => {
            for &value in data {
                let int_value = value.round() as i32;
                buffer.write_i32::<BigEndian>(int_value).map_err(|e| {
                    GiftiError::encode_error(format!("Failed to write INT32 value: {}", e))
                })?;
            }
        }
        (DataType::Int32, Endianness::LittleEndian) => {
            for &value in data {
                let int_value = value.round() as i32;
                buffer.write_i32::<LittleEndian>(int_value).map_err(|e| {
                    GiftiError::encode_error(format!("Failed to write INT32 value: {}", e))
                })?;
            }
        }
        (DataType::UInt32, Endianness::BigEndian) => {
            for &value in data {
                let uint_value = value.round() as u32;
                buffer.write_u32::<BigEndian>(uint_value).map_err(|e| {
                    GiftiError::encode_error(format!("Failed to write UINT32 value: {}", e))
                })?;
            }
        }
        (DataType::UInt32, Endianness::LittleEndian) => {
            for &value in data {
                let uint_value = value.round() as u32;
                buffer.write_u32::<LittleEndian>(uint_value).map_err(|e| {
                    GiftiError::encode_error(format!("Failed to write UINT32 value: {}", e))
                })?;
            }
        }
        (DataType::Float32, Endianness::BigEndian) => {
            for &value in data {
                let float_value = value as f32;
                buffer.write_f32::<BigEndian>(float_value).map_err(|e| {
                    GiftiError::encode_error(format!("Failed to write FLOAT32 value: {}", e))
                })?;
            }
        }
        (DataType::Float32, Endianness::LittleEndian) => {
            for &value in data {
                let float_value = value as f32;
                buffer.write_f32::<LittleEndian>(float_value).map_err(|e| {
                    GiftiError::encode_error(format!("Failed to write FLOAT32 value: {}", e))
                })?;
            }
        }
    }

    Ok(buffer)
}

/// Write binary data to an external file
pub fn write_external_binary_file(
    data: &[f64],
    filename: &str,
    data_type: DataType,
    endianness: Endianness,
) -> Result<()> {
    let binary_data = encode_binary_data(data, data_type, endianness)?;

    std::fs::write(filename, binary_data).map_err(|e| {
        GiftiError::encode_error(format!("Failed to write external file '{}': {}", filename, e))
    })
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_encode_ascii() {
        let data = vec![1.0, 2.0, 3.0];
        let result = encode_ascii(&data).unwrap();
        assert_eq!(result, "1 2 3");
    }

    #[test]
    fn test_encode_ascii_single_value() {
        let data = vec![42.0];
        let result = encode_ascii(&data).unwrap();
        assert_eq!(result, "42");
    }

    #[test]
    fn test_encode_base64_binary() {
        let data = vec![1.0, 2.0, 3.0];
        let result = encode_base64_binary(&data, DataType::Float32, Endianness::LittleEndian).unwrap();

        // The result should be a valid base64 string
        assert!(!result.is_empty());
        assert!(general_purpose::STANDARD.decode(&result).is_ok());
    }

    #[test]
    fn test_encode_gzip_base64_binary() {
        let data = vec![1.0, 2.0, 3.0];
        let result = encode_gzip_base64_binary(&data, DataType::Float32, Endianness::LittleEndian).unwrap();

        // The result should be a valid base64 string
        assert!(!result.is_empty());
        assert!(general_purpose::STANDARD.decode(&result).is_ok());
    }

    #[test]
    fn test_encode_data_ascii() {
        let data = vec![1.0, 2.0, 3.0];
        let result = encode_data(&data, Encoding::Ascii, DataType::Float32, Endianness::LittleEndian).unwrap();
        assert_eq!(result, "1 2 3");
    }

    #[test]
    fn test_encode_data_base64() {
        let data = vec![1.0, 2.0, 3.0];
        let result = encode_data(&data, Encoding::Base64Binary, DataType::Float32, Endianness::LittleEndian).unwrap();
        assert!(!result.is_empty());
    }

    #[test]
    fn test_encode_data_gzip_base64() {
        let data = vec![1.0, 2.0, 3.0];
        let result = encode_data(&data, Encoding::GZipBase64Binary, DataType::Float32, Endianness::LittleEndian).unwrap();
        assert!(!result.is_empty());
    }

    #[test]
    fn test_encode_data_external_file_error() {
        let data = vec![1.0, 2.0, 3.0];
        let result = encode_data(&data, Encoding::ExternalFileBinary, DataType::Float32, Endianness::LittleEndian);
        assert!(result.is_err());
    }
}

