mod tests {
    use super::*;
    use crate::core::data_array::DataArrayAttributes;
    use crate::io::reader::read_gifti_from_string;
    use tempfile::NamedTempFile;
    use std::io::Write as StdWrite;

    #[test]
    fn test_write_gifti_to_string() {
        // Create a simple GIFTI structure
        let mut gifti = Gifti::new();
        gifti.add_metadata("source".to_string(), "test".to_string());

        // Create a data array
        let data_array = DataArray::new_1d(
            vec![1.0, 2.0, 3.0],
            DataType::Float32,
            Encoding::Ascii,
            Intent::Shape,
        ).unwrap();

        gifti.add_data_array(data_array);

        // Write to string
        let xml_content = write_gifti_to_string(&gifti).unwrap();

        // Verify the XML contains expected elements
        assert!(xml_content.contains("<?xml version=\"1.0\" encoding=\"UTF-8\"?>"));
        assert!(xml_content.contains("<GIFTI Version=\"1.0\" NumberOfDataArrays=\"1\">"));
        assert!(xml_content.contains("<MetaData>"));
        assert!(xml_content.contains("Name=\"source\" Value=\"test\""));
        assert!(xml_content.contains("NIFTI_INTENT_SHAPE"));
        assert!(xml_content.contains("1 2 3"));
