//! GIFTI file writer implementation
//!
//! This module provides functionality to write GIFTI files with full XML generation.

use crate::core::gifti::Gifti;
use crate::core::data_array::DataArray;
use crate::core::types::{DataType, Encoding, Intent};
use crate::core::metadata::MetaData;
use crate::error::{GiftiError, Result};
use crate::io::encoder::encode_data;
use std::path::Path;
use std::fs;
use std::io::Write;
use quick_xml::Writer;
use quick_xml::events::{Event, BytesStart, BytesEnd, BytesText};

/// Write a GIFTI structure to a file
pub fn write_gifti<P: AsRef<Path>>(gifti: &Gifti, path: P) -> Result<()> {
    let xml_content = write_gifti_to_string(gifti)?;

    fs::write(path, xml_content)
        .map_err(|e| GiftiError::io_error(format!("Failed to write GIFTI file: {}", e)))
}

/// Write a GIFTI structure to a string
pub fn write_gifti_to_string(gifti: &Gifti) -> Result<String> {
    let mut buffer = Vec::new();
    let mut writer = Writer::new(&mut buffer);
    writer.write_event(Event::Decl(quick_xml::events::BytesDecl::new("1.0", Some("UTF-8"), None)))?;

    // Write GIFTI root element
    let mut gifti_start = BytesStart::new("GIFTI");
    gifti_start.push_attribute(("Version", gifti.version.as_str()));
    let num_arrays = gifti.data_arrays.len().to_string();
    gifti_start.push_attribute(("NumberOfDataArrays", num_arrays.as_str()));
    writer.write_event(Event::Start(gifti_start))?;

    // Write file-level metadata
    if !gifti.metadata.is_empty() {
        write_metadata(&mut writer, &gifti.metadata)?;
    }

    // Write label table if present
    if let Some(label_table) = &gifti.label_table {
        write_label_table(&mut writer, label_table)?;
    }

    // Write data arrays
    for data_array in &gifti.data_arrays {
        write_data_array(&mut writer, data_array)?;
    }

    // Close GIFTI root element
    writer.write_event(Event::End(BytesEnd::new("GIFTI")))?;

    String::from_utf8(buffer)
        .map_err(|e| GiftiError::io_error(format!("Failed to convert XML to string: {}", e)))
}

/// Write metadata section
fn write_metadata<W: Write>(writer: &mut Writer<W>, metadata: &MetaData) -> Result<()> {
    writer.write_event(Event::Start(BytesStart::new("MetaData")))?;

    for (key, value) in metadata.iter() {
        let mut md_start = BytesStart::new("MD");
        md_start.push_attribute(("Name", key.as_str()));
        md_start.push_attribute(("Value", value.as_str()));
        writer.write_event(Event::Empty(md_start))?;
    }

    writer.write_event(Event::End(BytesEnd::new("MetaData")))?;
    Ok(())
}

/// Write label table section
fn write_label_table<W: Write>(writer: &mut Writer<W>, label_table: &crate::core::metadata::LabelTable) -> Result<()> {
    writer.write_event(Event::Start(BytesStart::new("LabelTable")))?;

    for (index, label) in label_table.iter() {
        let mut label_start = BytesStart::new("Label");
        let key_str = index.to_string();
        let red_str = label.red.to_string();
        let green_str = label.green.to_string();
        let blue_str = label.blue.to_string();
        let alpha_str = label.alpha.to_string();

        label_start.push_attribute(("Key", key_str.as_str()));
        label_start.push_attribute(("Red", red_str.as_str()));
        label_start.push_attribute(("Green", green_str.as_str()));
        label_start.push_attribute(("Blue", blue_str.as_str()));
        label_start.push_attribute(("Alpha", alpha_str.as_str()));
        writer.write_event(Event::Start(label_start))?;

        writer.write_event(Event::Text(BytesText::new(&label.text)))?;

        writer.write_event(Event::End(BytesEnd::new("Label")))?;
    }

    writer.write_event(Event::End(BytesEnd::new("LabelTable")))?;
    Ok(())
}

/// Write data array section
fn write_data_array<W: Write>(writer: &mut Writer<W>, data_array: &DataArray) -> Result<()> {
    let mut data_array_start = BytesStart::new("DataArray");

    // Add DataArray attributes
    data_array_start.push_attribute(("Intent", data_array.attributes.intent.to_nifti_string()));
    data_array_start.push_attribute(("DataType", data_array.attributes.data_type.to_nifti_string()));
    let dimensionality = data_array.attributes.dimensions.len().to_string();
    data_array_start.push_attribute(("Dimensionality", dimensionality.as_str()));

    // Add dimension attributes
    for (i, &dim) in data_array.attributes.dimensions.iter().enumerate() {
        let attr_name = format!("Dim{}", i);
        let dim_str = dim.to_string();
        data_array_start.push_attribute((attr_name.as_str(), dim_str.as_str()));
    }

    data_array_start.push_attribute(("Encoding", data_array.attributes.encoding.to_gifti_string()));
    data_array_start.push_attribute(("Endian", data_array.attributes.endianness.to_gifti_string()));

    writer.write_event(Event::Start(data_array_start))?;

    // Write data array metadata
    if !data_array.metadata.is_empty() {
        write_metadata(writer, &data_array.metadata)?;
    }

    // Write data content
    write_data_content(writer, data_array)?;

    writer.write_event(Event::End(BytesEnd::new("DataArray")))?;
    Ok(())
}

/// Write data content based on encoding
fn write_data_content<W: Write>(writer: &mut Writer<W>, data_array: &DataArray) -> Result<()> {
    writer.write_event(Event::Start(BytesStart::new("Data")))?;

    // Encode the data according to the specified encoding
    let encoded_data = encode_data(
        &data_array.data,
        data_array.attributes.encoding,
        data_array.attributes.data_type,
        data_array.attributes.endianness,
    )?;

    // Write encoded data
    writer.write_event(Event::Text(BytesText::new(&encoded_data)))?;

    writer.write_event(Event::End(BytesEnd::new("Data")))?;
    Ok(())
}

